const QUESTIONS_CCSP_C7 = [
  { id:2101, domain:1, level:1, question:"In a generative AI service delivered as AI-as-a-Service, which shared-responsibility principle most accurately describes the customer's obligation?", options:["The customer must retrain the foundation model to meet its own security baseline","The provider assumes all liability for how customers use generated content downstream","The customer secures prompts, inputs, and how model outputs are consumed in their apps","The provider grants customers full root access to the underlying GPU infrastructure"], correct:2, explanation:"In AIaaS the provider secures the model and platform, but customers remain responsible for their prompts, data, and output handling. Claiming the provider assumes all downstream liability misstates the shared model." },
  { id:2102, domain:2, level:2, question:"A retrieval-augmented generation system stores embeddings in a vector database. Which control best protects sensitive source data represented by those embeddings?", options:["Assuming embeddings are irreversible and therefore need no access restrictions at all","Disabling logging on the vector database to reduce the total storage footprint","Publishing the embedding vectors publicly so any application can query them freely","Applying access controls, encryption, and tenant isolation to the vector store itself"], correct:3, explanation:"Embeddings can leak source content via inversion, so the vector store needs the same protections as sensitive data. Assuming embeddings are irreversible is a dangerous myth that ignores inversion attacks." },
  { id:2103, domain:3, level:2, question:"Confidential computing protects data in which state that traditional encryption at rest and in transit does not directly address?", options:["Data being archived to cold storage tiers for long-term compliance retention","Data in use while actively being processed inside a trusted execution environment","Data replicated asynchronously between two geographically separate regions","Data serialized into backup images stored on immutable object storage"], correct:1, explanation:"Confidential computing secures data in use within a TEE, complementing at-rest and in-transit controls. Cold archival and backups are at-rest scenarios already covered by conventional encryption." },
  { id:2104, domain:4, level:2, question:"Which practice best mitigates prompt injection in an LLM-backed web application that incorporates untrusted external content?", options:["Trusting model system prompts to fully override any conflicting user instructions","Treating retrieved content as untrusted and enforcing output validation and guardrails","Storing all user prompts in plaintext logs for later manual security review","Increasing the model temperature so responses become less deterministic overall"], correct:1, explanation:"External content must be treated as untrusted, with output validation and guardrails limiting injected instructions. System prompts alone cannot reliably override cleverly crafted injected instructions." },
  { id:2105, domain:5, level:1, question:"What is the primary purpose of AI red-teaming for a deployed large language model?", options:["Marketing the model's capabilities to prospective enterprise customers and partners","Optimizing GPU utilization to lower the monthly inference hosting bill","Automatically labeling training data to accelerate the next fine-tuning cycle","Adversarially probing the model to uncover harmful, biased, or exploitable behaviors"], correct:3, explanation:"AI red-teaming adversarially stress-tests a model to surface safety and security failures. Optimizing GPU cost or labeling data are operational tasks unrelated to adversarial testing." },
  { id:2106, domain:6, level:2, question:"Under the EU AI Act, systems classified as high-risk are primarily subject to which type of obligation?", options:["A blanket prohibition banning them from any deployment within the European market","Exemption from oversight provided the developer is headquartered outside Europe","A one-time registration fee with no continuing monitoring or documentation duties","Conformity assessments, risk management, and transparency requirements before deployment"], correct:3, explanation:"High-risk AI must undergo conformity assessment and ongoing risk management under the Act. Only a narrow set of unacceptable-risk uses are outright banned, not all high-risk systems." },
  { id:2107, domain:1, level:2, question:"Which statement best captures the role of the NIST AI Risk Management Framework in cloud AI governance?", options:["It mandates specific encryption algorithms every cloud AI workload must implement","It provides a voluntary structure to Govern, Map, Measure, and Manage AI risks","It certifies individual AI models as compliant after a government-run audit process","It replaces existing privacy regulations such as GDPR for all AI data processing"], correct:1, explanation:"The NIST AI RMF offers voluntary Govern, Map, Measure, and Manage functions for AI risk. It is not a certification scheme, nor does it supersede privacy laws like GDPR." },
  { id:2108, domain:2, level:3, question:"A membership inference attack against a cloud-hosted model primarily threatens which security property?", options:["The availability of the inference endpoint during periods of heavy concurrent load","The integrity of model weights stored in the provider's managed artifact registry","The non-repudiation of API calls made by authenticated downstream service accounts","The confidentiality of whether a specific record was part of the training dataset"], correct:3, explanation:"Membership inference reveals whether a data point was in the training set, breaching confidentiality. It does not target endpoint availability or the integrity of stored weights." },
  { id:2109, domain:3, level:2, question:"In a Kubernetes cluster, which control most directly limits lateral movement between pods?", options:["Increasing the replica count of each deployment to improve overall fault tolerance","Network policies that restrict pod-to-pod traffic to explicitly allowed connections","Assigning every pod the cluster-admin role to simplify service discovery logic","Disabling the audit log to reduce noise generated by routine control-plane calls"], correct:1, explanation:"Network policies enforce least-privilege east-west traffic, curbing lateral movement. Granting cluster-admin to all pods would drastically expand, not limit, attacker movement." },
  { id:2110, domain:4, level:3, question:"Insecure output handling from an LLM is best characterized as which class of vulnerability?", options:["A denial-of-service condition caused by excessively long generated token streams","A key-management failure where model API tokens are hardcoded into client apps","Downstream injection when unvalidated model output is passed to interpreters or browsers","A supply-chain flaw introduced by an unverified third-party base model artifact"], correct:2, explanation:"Insecure output handling occurs when model output is trusted and passed unsanitized to downstream systems, enabling XSS, SSRF, or code injection. It is distinct from DoS or key-management issues." },
  { id:2111, domain:5, level:2, question:"Which capability most distinguishes a CNAPP from a standalone CSPM tool?", options:["It only scans infrastructure-as-code templates before any deployment occurs","It unifies posture, workload, entitlement, and runtime protection in one platform","It replaces the need for any identity provider in a cloud environment","It exclusively manages TLS certificate rotation across load balancer fleets"], correct:3, explanation:"A CNAPP consolidates CSPM, CWPP, CIEM, and often IaC scanning into one platform. A pure CSPM focuses only on configuration posture, not integrated runtime and entitlement protection." },
  { id:2112, domain:6, level:1, question:"ISO/IEC 42001 provides organizations with what primary artifact?", options:["A hardware reference design for building tamper-resistant AI accelerator chips","A pricing model for calculating the total cost of cloud AI inference workloads","A management system standard for governing artificial intelligence responsibly","A cryptographic standard for post-quantum key exchange in AI microservices"], correct:2, explanation:"ISO/IEC 42001 defines an AI management system for responsible AI governance. It is a management standard, not a hardware design, pricing model, or cryptographic specification." },
  { id:2113, domain:1, level:1, question:"Zero trust architecture in the cloud is founded on which core assumption?", options:["Encryption alone eliminates the need for any authorization decisions at runtime","The internal corporate network can be trusted once a perimeter firewall exists","Trust is granted permanently after a single successful authentication event","No user, device, or workload is inherently trusted regardless of network location"], correct:3, explanation:"Zero trust assumes no implicit trust and verifies every request continuously. Trusting the internal network by default is exactly the perimeter model zero trust replaces." },
  { id:2114, domain:2, level:2, question:"To prevent PII leakage into an LLM, which pre-processing control is most effective at the prompt stage?", options:["Increasing the maximum context window so the model can hold more conversation","Raising the model's temperature to make outputs less predictable to attackers","Storing the full raw prompt in an analytics warehouse for product improvement","Redacting or tokenizing sensitive identifiers before the prompt reaches the model"], correct:3, explanation:"Redaction or tokenization of PII before it reaches the model prevents sensitive data exposure. Expanding the context window or raising temperature does nothing to protect PII." },
  { id:2115, domain:3, level:3, question:"A trusted execution environment provides attestation primarily to achieve what assurance?", options:["That code and data run in a genuine, unmodified enclave before secrets are released","That storage volumes attached to the enclave are automatically deduplicated","That the workload will always complete within a guaranteed maximum latency budget","That the cloud provider can inspect enclave memory for compliance auditing"], correct:0, explanation:"Attestation proves the enclave is authentic and unmodified before secrets are provisioned. A TEE is designed so the provider cannot inspect enclave memory, contradicting that option." },
  { id:2116, domain:4, level:2, question:"Which measure best reduces the risk of training-data poisoning in an MLOps pipeline?", options:["Allowing any contributor to push directly to the production training dataset","Data provenance tracking with validation and integrity checks on ingested data","Disabling model versioning to keep the artifact registry small and manageable","Skipping evaluation steps to accelerate the continuous retraining schedule"], correct:3, explanation:"Provenance tracking plus validation and integrity checks defend against poisoned training data. Allowing unrestricted pushes or skipping evaluation would increase poisoning risk, not reduce it." },
  { id:2117, domain:5, level:2, question:"SASE converges networking and security by delivering which combination from the cloud edge?", options:["On-premises appliance stacks managed manually at each individual branch office","SD-WAN with security services such as SWG, CASB, ZTNA, and firewall-as-a-service","A single monolithic VPN concentrator located in one central corporate datacenter","Physical media destruction services for decommissioned hardware storage drives"], correct:1, explanation:"SASE unifies SD-WAN with cloud-delivered SWG, CASB, ZTNA, and FWaaS. Centralized VPN concentrators and on-prem appliance stacks are the legacy model SASE replaces." },
  { id:2118, domain:6, level:2, question:"A model extraction attack against a cloud ML API primarily aims to accomplish what?", options:["Overwhelm the endpoint with traffic until legitimate requests are denied service","Steal the API gateway's TLS private key to decrypt captured network traffic","Corrupt the training dataset so future model versions produce biased outputs","Reconstruct or approximate the proprietary model by systematically querying it"], correct:3, explanation:"Model extraction reconstructs a functional copy of a model through crafted queries, stealing IP. Flooding for denial of service or corrupting training data describe different attack classes." },
  { id:2119, domain:1, level:2, question:"AI TRiSM (Trust, Risk, and Security Management) is best described as which of the following?", options:["A single vendor product that automatically certifies models as fully compliant","A framework of practices ensuring AI models are trustworthy, governed, and secure","A cryptographic protocol securing model weights during federated learning rounds","A billing dashboard that tracks per-token inference costs across cloud regions"], correct:1, explanation:"AI TRiSM is a framework of governance, trust, risk, and security practices for AI. It is not a single product, a cryptographic protocol, or a billing tool." },
  { id:2120, domain:2, level:1, question:"Data sovereignty most directly concerns which of the following?", options:["Data being subject to the laws of the jurisdiction where it physically resides","The compression ratio achieved when archiving datasets to cold storage","The number of replicas maintained to guarantee durability of stored objects","The speed at which encrypted backups can be restored following an outage"], correct:0, explanation:"Data sovereignty means data is governed by the laws of the country where it is stored. Backup restore speed, compression, and replica counts are operational concerns, not sovereignty." },
  { id:2121, domain:3, level:2, question:"In serverless computing, which security concern is most amplified compared to traditional VMs?", options:["The physical security of the datacenter racks hosting the compute nodes","Over-permissioned function roles and expanded event-driven attack surface","The need to manually patch the guest operating system on each function","The cost of maintaining always-on idle capacity between invocation events"], correct:1, explanation:"Serverless multiplies fine-grained functions, so over-permissioned roles and event triggers become the key risk. The provider patches the OS, so guest patching is not the customer's concern." },
  { id:2122, domain:4, level:3, question:"A model inversion attack differs from membership inference in that it primarily attempts to do what?", options:["Determine whether a single specific record was present in the training corpus","Reconstruct representative features of the training data from model outputs","Flood the model endpoint to exhaust its provisioned inference capacity","Inject malicious instructions through a crafted user prompt at runtime"], correct:1, explanation:"Model inversion reconstructs features of training data from outputs, whereas membership inference only tests whether a record was included. The two attacks target different disclosures." },
  { id:2123, domain:5, level:2, question:"Which secrets-management practice best supports a cloud-native microservices deployment?", options:["Using a centralized vault with short-lived, dynamically issued credentials","Sharing one static credential across all services to simplify rotation efforts","Committing environment secrets to the Git repository for version tracking","Embedding long-lived API keys directly into container images for portability"], correct:0, explanation:"A central vault issuing short-lived dynamic credentials limits exposure and eases rotation. Embedding keys in images or committing them to Git creates persistent, hard-to-revoke secrets." },
  { id:2124, domain:6, level:2, question:"An SBOM (software bill of materials) most directly improves an organization's ability to do what?", options:["Automatically scale container replicas based on real-time CPU utilization","Accelerate CI/CD pipeline execution by caching build artifacts more aggressively","Encrypt data in transit between microservices without configuring TLS certificates","Identify and respond to vulnerabilities in third-party and open-source components"], correct:3, explanation:"An SBOM inventories components so teams can quickly locate affected dependencies during a vulnerability event. It does not speed builds, encrypt traffic, or drive autoscaling." },
  { id:2125, domain:1, level:2, question:"Post-quantum cryptography readiness in cloud environments primarily addresses which threat?", options:["Insider misuse of privileged administrative access to management consoles","Misconfigured storage buckets exposing data to anonymous internet users","Distributed denial-of-service floods targeting public API endpoints as a general practice","Harvest-now-decrypt-later attacks where captured ciphertext is broken by future quantum computers"], correct:3, explanation:"Post-quantum readiness counters harvest-now-decrypt-later, where adversaries store ciphertext to break later with quantum computers. Insider misuse and DDoS are unrelated threat classes." },
  { id:2126, domain:2, level:3, question:"When securing a RAG pipeline, why is document-level access control important at retrieval time?", options:["It prevents users from retrieving context they are not authorized to see","It guarantees the model will never hallucinate facts absent from the corpus","It ensures the model reduces its response latency during high query volumes","It reduces the embedding dimensionality and therefore lowers vector storage costs"], correct:0, explanation:"Enforcing per-document authorization at retrieval prevents users from surfacing unauthorized context through the model. Access control neither eliminates hallucination nor affects latency." },
  { id:2127, domain:3, level:2, question:"A service mesh such as Istio most directly enhances security by providing which capability?", options:["Physical isolation of tenant workloads onto dedicated bare-metal hosts","Automatic mutual TLS and fine-grained authorization between microservices","Real-time deduplication of log data written to object storage backends","Guaranteed elimination of all application-layer input validation flaws"], correct:1, explanation:"A service mesh provides transparent mTLS and policy-based authorization for service-to-service traffic. It does not offer physical isolation or remove the need for application input validation." },
  { id:2128, domain:4, level:2, question:"Which control best addresses the risk of an LLM leaking data through hallucinated but plausible outputs?", options:["Increasing the maximum output token limit so responses are more complete","Human review and grounding responses with cited, verifiable retrieved sources","Disabling all logging so hallucinated content is never persisted anywhere","Raising temperature to encourage more creative and varied model responses"], correct:1, explanation:"Grounding outputs in cited sources and adding human review reduces reliance on fabricated content. Higher temperature and larger token limits tend to increase, not reduce, hallucination risk." },
  { id:2129, domain:5, level:1, question:"What is the primary function of a CWPP in a cloud environment?", options:["Protecting workloads such as VMs, containers, and serverless functions at runtime","Issuing and rotating the organization's public key infrastructure certificates","Negotiating enterprise licensing agreements with cloud service providers","Managing DNS records and routing traffic across multiple cloud regions"], correct:0, explanation:"A CWPP secures workloads across VMs, containers, and serverless during runtime. DNS management, PKI issuance, and licensing are outside its scope." },
  { id:2130, domain:6, level:2, question:"ISO/IEC 23894 provides guidance primarily on which subject?", options:["Network segmentation requirements for payment card industry environments","Physical destruction standards for decommissioned solid-state storage media","Risk management guidance specifically tailored to artificial intelligence systems","Accessibility standards for consumer-facing mobile application interfaces"], correct:2, explanation:"ISO/IEC 23894 offers AI-specific risk management guidance aligned with ISO 31000. It does not address media destruction, PCI segmentation, or accessibility." },
  { id:2131, domain:1, level:3, question:"Why is the AI model supply chain considered a distinct security concern in cloud deployments?", options:["Models always execute faster when downloaded from a public model repository","Model artifacts are inherently immune to tampering because of their large file size","Foundation models cannot be fine-tuned once they are published to a registry","Pre-trained models and datasets from third parties may contain hidden backdoors or poisoning"], correct:3, explanation:"Third-party models and datasets can carry backdoors or poisoned data, making provenance verification essential. Large file size provides no tamper resistance whatsoever." },
  { id:2132, domain:2, level:2, question:"Which approach best protects data residency requirements for a multinational SaaS deployment?", options:["Replicating all customer data to every available region for maximum redundancy","Region-pinning data so records remain within the required legal jurisdiction","Storing all data in a single global region regardless of customer nationality","Encrypting data so its physical storage location becomes legally irrelevant"], correct:1, explanation:"Region-pinning keeps data within the mandated jurisdiction to satisfy residency law. Encryption does not exempt data from residency obligations tied to its physical location." },
  { id:2133, domain:3, level:2, question:"A CIEM tool primarily helps organizations manage which risk?", options:["Excessive and unused cloud identity permissions that expand the attack surface","Insufficient bandwidth between availability zones during traffic spikes","Outdated TLS cipher suites configured on public-facing load balancers","Inadequate physical cooling capacity within the provider's datacenters"], correct:0, explanation:"CIEM focuses on right-sizing entitlements and removing excessive permissions across cloud identities. Bandwidth, cipher suites, and cooling are unrelated operational domains." },
  { id:2134, domain:4, level:3, question:"Which design choice most effectively limits the blast radius of a jailbreak that bypasses an LLM's guardrails?", options:["Granting the model broad tool access so it can self-correct any harmful action","Trusting the model to refuse all malicious requests without external constraints","Logging jailbreak attempts only after damage to downstream systems occurs","Constraining the model's tools and privileges via least-privilege system boundaries"], correct:3, explanation:"Least-privilege boundaries on tools and actions contain harm even when a jailbreak succeeds. Granting broad access or trusting the model to police itself increases the blast radius." },
  { id:2135, domain:5, level:2, question:"In securing an MLOps pipeline, why should model artifacts be signed?", options:["Signing verifies artifact integrity and origin, preventing tampered models from deploying","Signing compresses the model file to reduce container image pull times","Signing automatically converts the model into a quantization-optimized format","Signing removes the need to scan container images for known vulnerabilities"], correct:0, explanation:"Artifact signing lets the pipeline verify integrity and provenance before deployment. It neither compresses files, changes precision, nor replaces vulnerability scanning." },
  { id:2136, domain:6, level:1, question:"Responsible AI principles most commonly emphasize which combination of attributes?", options:["Fairness, transparency, accountability, and privacy in AI system design","Maximum model size, lowest latency, and highest possible token throughput","Exclusive reliance on closed-source models to protect intellectual property","Elimination of all human oversight to maximize automation efficiency"], correct:0, explanation:"Responsible AI centers on fairness, transparency, accountability, and privacy. Removing human oversight or chasing raw performance contradicts responsible AI goals." },
  { id:2137, domain:1, level:2, question:"Which statement best describes the shared responsibility shift when moving from IaaS to a managed AI platform (PaaS-like AIaaS)?", options:["The customer gains responsibility for hypervisor patching and physical security","Responsibility is identical across every service model regardless of abstraction level","The customer must now manage the underlying GPU firmware and driver updates","The provider assumes more of the stack, leaving customers to secure data and usage"], correct:3, explanation:"Higher-abstraction AI platforms shift more stack responsibility to the provider, focusing customers on data and usage. Customers do not take on hypervisor or firmware duties in that model." },
  { id:2138, domain:2, level:2, question:"Tokenization differs from encryption in that tokenization primarily does what?", options:["Applies an asymmetric key pair to protect data during network transmission","Compresses the plaintext before storing it to conserve database capacity","Substitutes sensitive values with non-sensitive tokens that have no mathematical link","Generates a fixed-length hash used to verify the integrity of a message"], correct:2, explanation:"Tokenization replaces sensitive data with unrelated tokens, with the mapping held in a secure vault. Encryption, by contrast, uses reversible keyed algorithms, and hashing is one-way." },
  { id:2139, domain:3, level:3, question:"When adopting confidential computing for a multi-tenant AI inference service, which trade-off should architects anticipate?", options:["Enclaves eliminate the need for any network segmentation between tenants","Confidential computing removes the requirement to encrypt data at rest","Attestation makes the workload immune to all application-layer vulnerabilities","Performance overhead and a smaller trusted memory footprint constrain workloads"], correct:3, explanation:"TEEs impose performance overhead and limited enclave memory that constrain workloads. They do not remove the need for network segmentation, at-rest encryption, or app-layer security." },
  { id:2140, domain:4, level:2, question:"Which is the most appropriate guardrail for preventing an LLM from returning executable code that could be run unsafely?", options:["Sanitizing and sandboxing model output before any execution or rendering occurs","Increasing the model's context window to include more of the conversation","Disabling the model's safety filters to avoid blocking legitimate developer queries","Allowing the client to execute any returned code automatically for convenience"], correct:0, explanation:"Sanitizing and sandboxing output before execution prevents unsafe code from causing harm. Auto-executing returned code or disabling safety filters removes exactly the controls needed." },
  { id:2141, domain:5, level:2, question:"A CSPM tool continuously performs which primary function?", options:["Providing runtime memory protection for individual container processes","Encrypting all inter-service traffic using automatically rotated session keys","Detecting misconfigurations and compliance drift across cloud resource settings","Managing the lifecycle of user identities in the corporate directory"], correct:2, explanation:"CSPM continuously scans for misconfigurations and compliance drift in cloud posture. Runtime memory protection and identity lifecycle belong to CWPP and IAM respectively." },
  { id:2142, domain:6, level:3, question:"Under the EU AI Act, which practice is generally classified as an unacceptable-risk (prohibited) use?", options:["Deploying an AI chatbot that clearly discloses it is an automated system","Using AI to recommend products based on a customer's stated preferences","Government social scoring that ranks citizens leading to detrimental treatment","Applying AI to detect fraudulent transactions within a banking platform"], correct:2, explanation:"Government social scoring producing detrimental treatment is a prohibited unacceptable-risk practice. Disclosed chatbots, recommendations, and fraud detection are permitted with appropriate obligations." },
  { id:2143, domain:1, level:1, question:"What does the term data provenance mean in the context of AI systems?", options:["The documented origin, lineage, and transformations of data used by a model","The physical distance between the data source and the inference endpoint","The compression algorithm applied to datasets before they are stored","The total monetary cost of acquiring a commercial training dataset"], correct:0, explanation:"Data provenance is the traceable origin and transformation history of data. It is not about physical distance, compression, or acquisition cost." },
  { id:2144, domain:2, level:2, question:"Which risk is uniquely introduced when embeddings of confidential documents are stored in a shared vector database?", options:["Embeddings automatically expire and are deleted after a fixed retention window","Cross-tenant retrieval could expose confidential context to unauthorized tenants","Vector databases cannot support similarity search over high-dimensional data","Embeddings increase network latency to the point that queries always time out"], correct:1, explanation:"Without strong tenant isolation, one tenant's query could retrieve another tenant's confidential embeddings. Vector databases do support similarity search and do not auto-expire by default." },
  { id:2145, domain:3, level:2, question:"Which practice best hardens a container image before deployment?", options:["Running every container as the root user to avoid permission complications","Using minimal base images and scanning for known vulnerabilities before release","Pulling images from unverified public registries to save build pipeline time","Including a full general-purpose OS with all packages for maximum flexibility"], correct:1, explanation:"Minimal base images plus vulnerability scanning shrink the attack surface. Running as root, bundling full OSes, and using unverified registries all increase risk." },
  { id:2146, domain:4, level:3, question:"An indirect prompt injection is distinguished from a direct prompt injection by which characteristic?", options:["The attack requires physical access to the datacenter hosting the model","The attacker types the malicious instruction directly into the chat interface","The malicious instruction is embedded in external content the model later ingests","The injection only affects the model's training phase and never inference"], correct:2, explanation:"Indirect injection hides instructions in external data (web pages, documents) that the model consumes later. Direct injection is when the attacker types instructions straight into the prompt." },
  { id:2147, domain:5, level:2, question:"Why is continuous monitoring of AI model behavior in production important beyond initial testing?", options:["Because model weights physically degrade over time on the storage medium","Because monitoring reduces the electricity consumed by the inference cluster","Because model drift and emergent misuse can appear only after real-world deployment","Because it eliminates the need to ever retrain or update the deployed model"], correct:2, explanation:"Continuous monitoring catches drift, abuse, and emergent behaviors that surface only in production. Monitoring does not affect power draw and certainly does not remove retraining needs." },
  { id:2148, domain:6, level:2, question:"The 'Measure' function of the NIST AI RMF is chiefly concerned with which activity?", options:["Analyzing, assessing, and tracking identified AI risks using metrics","Purchasing cyber-insurance coverage for potential AI-related liabilities","Assigning organizational accountability and defining AI governance policies","Marketing the trustworthiness of AI products to external stakeholders"], correct:0, explanation:"The Measure function analyzes and tracks AI risks with quantitative and qualitative metrics. Accountability and policy fall under Govern, not Measure." },
  { id:2149, domain:1, level:2, question:"In a zero trust cloud model, micro-segmentation primarily achieves what outcome?", options:["Consolidating all traffic through a single flat network for easier monitoring","Guaranteeing every workload receives an identical amount of network bandwidth","Removing the need for identity verification within a trusted internal segment","Isolating workloads into granular zones so a breach cannot spread freely"], correct:3, explanation:"Micro-segmentation confines a compromise to a small zone, limiting lateral movement. Zero trust still verifies identity everywhere and avoids flat trusted segments." },
  { id:2150, domain:2, level:1, question:"Which technique allows computation on encrypted data without first decrypting it?", options:["Transparent data encryption applied at the database storage engine layer","Full-disk encryption protecting data on the underlying block storage device","Symmetric session encryption negotiated during a TLS handshake exchange","Homomorphic encryption performing operations directly on ciphertext values"], correct:3, explanation:"Homomorphic encryption enables computation directly on ciphertext. TDE, TLS, and full-disk encryption all require decryption before the data can be processed." },
  { id:2151, domain:3, level:2, question:"Which is a key benefit of infrastructure-as-code scanning within a cloud-native pipeline?", options:["It detects insecure configurations before resources are provisioned in the cloud","It guarantees zero downtime during every production deployment window","It replaces the need for runtime workload protection entirely","It automatically negotiates lower pricing with the cloud provider"], correct:0, explanation:"IaC scanning shifts security left by catching misconfigurations before provisioning. It does not guarantee zero downtime, replace runtime protection, or influence pricing." },
  { id:2152, domain:4, level:2, question:"Which OWASP LLM risk describes an application over-relying on model output for critical decisions without oversight?", options:["Model theft where proprietary weights are exfiltrated from the host","Prompt injection through crafted adversarial user or external inputs","Training-data poisoning that corrupts the model during its learning phase","Excessive agency granted to the model to take autonomous consequential actions"], correct:3, explanation:"Excessive agency is when a model is granted too much autonomy to act without oversight. Prompt injection, poisoning, and theft are separate OWASP LLM risk categories." },
  { id:2153, domain:5, level:3, question:"When integrating an LLM agent with external tools, which control most reduces the risk of unintended destructive actions?", options:["Requiring human-in-the-loop approval for high-impact or irreversible tool calls","Trusting the LLM to always interpret ambiguous instructions correctly","Allowing the agent to call any API endpoint reachable from its network","Removing all logging so the agent can operate at maximum speed"], correct:0, explanation:"Human-in-the-loop approval for high-impact actions prevents autonomous destructive operations. Unrestricted API access and blind trust in interpretation increase risk instead." },
  { id:2154, domain:6, level:2, question:"Data protection impact assessments (DPIAs) for AI systems are primarily intended to accomplish what?", options:["Benchmark the model's accuracy against competing commercial offerings","Optimize the inference cost per token across multiple cloud regions","Systematically evaluate privacy risks to individuals before processing begins","Certify that the model meets ISO 42001 without any further audit steps"], correct:3, explanation:"A DPIA evaluates privacy risks to individuals before high-risk processing. It is not an accuracy benchmark, a cost optimizer, or a substitute for ISO 42001 certification." },
  { id:2155, domain:1, level:2, question:"Which characteristic best defines a foundation model relevant to cloud AI security planning?", options:["A model whose weights are always publicly disclosed and freely modifiable","A lightweight rule-based system requiring no training data whatsoever","A model that can only be used for a single narrowly defined classification task","A large model pre-trained on broad data and adaptable to many downstream tasks"], correct:3, explanation:"Foundation models are broadly pre-trained and adaptable across many tasks. They are neither rule-based, single-task, nor necessarily open-weight." },
  { id:2156, domain:2, level:2, question:"Which control most directly mitigates the risk of sensitive data being memorized and later regurgitated by a model?", options:["Increasing the number of training epochs to improve model convergence","Publishing the model weights so the community can audit them freely","Serving the model from more geographic regions to reduce latency","Applying differential privacy and de-duplication during model training"], correct:3, explanation:"Differential privacy and de-duplication reduce memorization of individual records. More epochs can worsen memorization, and publishing weights does not prevent regurgitation." },
  { id:2157, domain:3, level:3, question:"In a Kubernetes environment, why is admission control (e.g., policy-as-code gating) valuable for security?", options:["It automatically doubles the CPU allocated to every deployed pod","It rejects non-compliant workloads before they are scheduled onto the cluster","It encrypts all persistent volumes without any additional configuration","It removes the need for role-based access control on the API server"], correct:1, explanation:"Admission controllers enforce policy and reject non-compliant workloads at deploy time. They do not adjust CPU, encrypt volumes automatically, or replace RBAC." },
  { id:2158, domain:4, level:2, question:"Which is the best defense-in-depth measure for handling user-supplied files fed into an LLM document-analysis feature?", options:["Trusting file extensions to determine whether the content is safe to process","Passing raw file bytes directly into the model without any inspection","Scanning, validating type, and sandboxing files before model processing","Disabling antivirus scanning to speed up the document ingestion pipeline"], correct:2, explanation:"Scanning, type validation, and sandboxing prevent malicious files from reaching the model or backend. Trusting extensions or skipping scanning leaves the pipeline exposed." },
  { id:2159, domain:5, level:1, question:"What does CIEM stand for in cloud security tooling?", options:["Centralized Incident Escalation Model for coordinating response workflows","Container Image Encryption Method for securing registry artifacts at rest","Cloud Infrastructure Entitlement Management for governing identity permissions","Continuous Integration Environment Manager for orchestrating build pipelines"], correct:2, explanation:"CIEM is Cloud Infrastructure Entitlement Management, focused on right-sizing identity permissions. The other expansions are fabricated and unrelated to the acronym." },
  { id:2160, domain:6, level:2, question:"Why is a clear AI use policy important for compliance when employees use public generative AI tools?", options:["It guarantees the generative AI vendor will indemnify all corporate liability","It automatically anonymizes any data typed into external AI chat services","It prevents inadvertent disclosure of confidential data into third-party models","It eliminates the organization's obligations under applicable privacy laws"], correct:2, explanation:"A clear policy curbs employees pasting confidential data into third-party models. It cannot force vendor indemnification, auto-anonymize input, or waive legal obligations." },
  { id:2161, domain:1, level:3, question:"Which architectural pattern best supports trustworthy AI by keeping sensitive data on-premises while using cloud models?", options:["Uploading all raw sensitive data to the cloud model for centralized processing","Broadcasting the full dataset to every region hosting a model replica","Retrieval augmentation where only necessary, minimized context is sent to the model","Disabling encryption so the model can process data with lower overhead"], correct:2, explanation:"Sending only minimized, necessary context via retrieval keeps most sensitive data local. Uploading everything or broadcasting datasets contradicts data-minimization principles." },
  { id:2162, domain:2, level:2, question:"Which is the most effective way to prevent secrets from leaking through an LLM's responses?", options:["Storing all secrets inside the model's system prompt for quick reference","Relying solely on the model to recognize and refuse to reveal secrets","Never placing secrets in prompts and enforcing output filtering for sensitive patterns","Logging every response containing secrets for later security investigation"], correct:2, explanation:"Keeping secrets out of prompts and filtering outputs prevents leakage at the source. Storing secrets in the system prompt or trusting the model to self-censor is unreliable." },
  { id:2163, domain:3, level:2, question:"Which statement about serverless function cold starts is most relevant to security architecture?", options:["Cold starts guarantee that each invocation runs on freshly patched hardware","Cold starts eliminate the need for least-privilege execution roles on functions","Cold starts make persistent in-memory malware harder but not impossible to sustain","Cold starts encrypt all environment variables automatically at invocation time"], correct:2, explanation:"Ephemeral execution complicates persistent in-memory implants, though transient abuse remains possible. Cold starts do not manage patching, roles, or environment-variable encryption." },
  { id:2164, domain:4, level:3, question:"Why does insecure plugin or tool design in an LLM application often escalate the impact of prompt injection?", options:["Because plugins reduce the model's context window and cause truncation errors","Because injected instructions can invoke powerful tools to reach backend systems","Because plugins always run on separate hardware isolated from the model","Because tool calls are inherently encrypted and cannot carry malicious payloads"], correct:1, explanation:"Powerful, over-privileged tools let an injected prompt pivot into backend systems, amplifying impact. Plugins do not inherently isolate execution or encrypt malicious payloads away." },
  { id:2165, domain:5, level:2, question:"Which logging practice best supports incident investigation for a cloud LLM application?", options:["Capturing prompts, responses, and tool calls with appropriate privacy safeguards","Logging only successful requests to keep the log volume manageable","Disabling logging entirely to avoid storing any potentially sensitive content","Storing logs only on the ephemeral local disk of each inference container"], correct:0, explanation:"Comprehensive but privacy-aware logging of prompts, responses, and tool calls enables investigation. Logging only successes or using ephemeral local disks loses critical evidence." },
  { id:2166, domain:6, level:1, question:"Algorithmic transparency in AI governance most directly supports which stakeholder need?", options:["Understanding how and why an AI system reached a particular decision","Reducing the model's inference latency for real-time applications","Lowering the cloud storage cost of retaining historical training data","Increasing the raw parameter count to improve benchmark scores"], correct:0, explanation:"Transparency helps stakeholders understand AI decisions, supporting accountability and trust. It is unrelated to latency, storage cost, or parameter counts." },
  { id:2167, domain:1, level:2, question:"Which best describes the security relevance of guardrails in a generative AI deployment?", options:["They permanently fine-tune the base model to remove all unsafe knowledge","They physically isolate GPU memory between concurrent inference requests","They are policy layers that filter inputs and outputs to enforce safe behavior","They guarantee mathematically that the model can never be jailbroken"], correct:2, explanation:"Guardrails are input/output policy layers that constrain unsafe behavior at runtime. They do not retrain the model, isolate GPU memory, or offer mathematical jailbreak-proof guarantees." },
  { id:2168, domain:2, level:2, question:"Which data-security control is most appropriate for protecting training datasets from unauthorized modification?", options:["Storing datasets in world-readable buckets to simplify data science access","Compressing datasets so their contents cannot be easily interpreted","Integrity verification with cryptographic hashing and immutable versioned storage","Deleting datasets immediately after each training run to reduce exposure"], correct:2, explanation:"Cryptographic hashing plus immutable versioning detects and prevents unauthorized modification. World-readable buckets and compression do nothing to protect integrity." },
  { id:2169, domain:3, level:3, question:"Which factor most complicates forensic investigation in ephemeral cloud-native environments?", options:["Ephemeral workloads run only on physical mainframes without virtualization","Cloud providers refuse to offer any logging or monitoring capabilities","Containers and functions are short-lived, so volatile evidence disappears quickly","Container runtimes prevent any form of centralized log aggregation"], correct:2, explanation:"Short-lived containers and functions destroy volatile evidence rapidly, complicating forensics. Providers do offer logging, and centralized aggregation is entirely feasible." },
  { id:2170, domain:4, level:2, question:"Which is a sound approach to rate-limiting an LLM API to reduce abuse and model-extraction risk?", options:["Removing all quotas so legitimate users never experience throttling delays","Allowing unlimited anonymous access to maximize product adoption metrics","Applying per-identity request quotas and anomaly detection on query patterns","Blocking only requests that originate from known corporate IP ranges"], correct:2, explanation:"Per-identity quotas plus anomaly detection curb extraction and abuse. Removing quotas or allowing unlimited anonymous access directly enables extraction attacks." },
  { id:2171, domain:5, level:2, question:"Why is workload identity (rather than static keys) preferred for service-to-service authentication in the cloud?", options:["It permanently disables auditing so authentication events are never recorded","It provides short-lived, automatically rotated credentials tied to the workload","It requires embedding a shared password into every microservice image","It removes the need to authorize any actions once identity is established"], correct:1, explanation:"Workload identity issues short-lived, auto-rotated credentials, avoiding long-lived static secrets. It still requires authorization and does not disable auditing." },
  { id:2172, domain:6, level:3, question:"A cloud customer using an AIaaS offering must still address which compliance obligation directly?", options:["Patching the provider's underlying inference accelerator firmware promptly","Physically securing the datacenter where the provider hosts the models","Ensuring their own use of the AI and the data they submit meets applicable laws","Publishing the provider's proprietary model architecture for regulatory review"], correct:2, explanation:"The customer remains accountable for lawful use and the data they submit, even with AIaaS. Firmware patching and datacenter security are the provider's responsibilities." },
  { id:2173, domain:1, level:1, question:"What is the primary goal of an AI management system under ISO/IEC 42001?", options:["Establishing governance to develop and use AI responsibly and systematically","Maximizing the throughput of the organization's GPU training clusters","Guaranteeing that AI models achieve state-of-the-art accuracy benchmarks","Eliminating the need for any human involvement in AI decision-making"], correct:0, explanation:"An AIMS under ISO 42001 establishes responsible, systematic AI governance. It is not about maximizing throughput, benchmark accuracy, or removing human involvement." },
  { id:2174, domain:2, level:2, question:"Which practice best addresses the risk of sensitive data appearing in LLM fine-tuning datasets?", options:["Fine-tuning on the largest possible dataset regardless of its data sensitivity","Assuming fine-tuning cannot memorize any of the underlying training examples","Data classification and minimization to exclude sensitive records before training","Skipping any review of training data to accelerate the fine-tuning schedule"], correct:2, explanation:"Classifying and minimizing data keeps sensitive records out of fine-tuning sets. Assuming no memorization occurs, or skipping review, ignores well-documented memorization risks." },
  { id:2175, domain:3, level:2, question:"Which is the strongest control against container escape to the host operating system?", options:["Running privileged containers so they can manage their own isolation","Kernel hardening, seccomp/AppArmor profiles, and avoiding privileged mode","Granting containers direct access to the host's Docker socket for flexibility","Disabling namespace isolation to simplify inter-container communication"], correct:1, explanation:"Kernel hardening, seccomp/AppArmor, and dropping privileged mode reduce container escape risk. Privileged containers, host socket access, and disabling namespaces make escape easier." },
  { id:2176, domain:4, level:3, question:"When an LLM application uses function-calling, why should returned arguments be validated server-side?", options:["Because client-side validation is always sufficient to guarantee argument safety","Because validation increases the model's temperature and creativity","Because the model may produce malformed or malicious arguments that reach backends","Because server-side validation removes the need for authentication on the API"], correct:2, explanation:"The model can emit malformed or malicious arguments, so backends must validate them independently. Client-side checks are bypassable and validation never replaces authentication." },
  { id:2177, domain:5, level:2, question:"Which SIEM enhancement is most useful for detecting LLM-specific abuse in production?", options:["Ingesting only infrastructure metrics while ignoring all application-layer events","Correlating prompt/response telemetry with anomaly detection for injection patterns","Disabling alerting to reduce analyst fatigue from generative AI workloads","Storing logs without timestamps to simplify the schema of the data lake"], correct:1, explanation:"Correlating prompt/response telemetry with anomaly detection surfaces injection and abuse patterns. Ignoring app-layer events, disabling alerts, or dropping timestamps all undermine detection." },
  { id:2178, domain:6, level:2, question:"The 'Govern' function of the NIST AI RMF primarily establishes what within an organization?", options:["The specific GPU hardware standard required for all training workloads","A culture, policies, and accountability structure for managing AI risk","A fixed pricing agreement with the organization's cloud AI provider","An automated tool that certifies models as compliant without human input"], correct:1, explanation:"Govern establishes the culture, policies, and accountability underpinning AI risk management. It is not a hardware standard, pricing agreement, or automated certification tool." },
  { id:2179, domain:1, level:2, question:"Which best explains why SSE (Security Service Edge) is often adopted alongside cloud migration?", options:["It delivers security services like SWG, CASB, and ZTNA from the cloud edge","It requires backhauling all traffic to a central datacenter for inspection","It eliminates the need for any identity provider in the architecture","It physically relocates servers closer to end users for lower latency"], correct:0, explanation:"SSE delivers cloud-edge security (SWG, CASB, ZTNA) suited to distributed cloud access. It avoids datacenter backhauling and does not remove the need for identity providers." },
  { id:2180, domain:2, level:1, question:"Which term describes deliberately corrupting input data to a model to cause misclassification at inference time?", options:["A homomorphic transformation applied to protect data confidentiality","An adversarial example crafted to fool the model into a wrong prediction","A data-residency control enforcing jurisdictional storage boundaries","A tokenization process replacing sensitive values with surrogate tokens"], correct:1, explanation:"Adversarial examples are perturbed inputs designed to cause misclassification. Homomorphic transforms, residency controls, and tokenization are unrelated defensive or privacy concepts." },
  { id:2181, domain:3, level:3, question:"Which design most effectively limits the impact of a compromised node in a multi-tenant Kubernetes platform?", options:["Placing all tenant workloads in a single shared namespace for efficiency","Granting all service accounts cluster-wide permissions to ease debugging","Strong tenant isolation with separate node pools, namespaces, and network policies","Disabling pod security standards to accommodate legacy tenant workloads"], correct:2, explanation:"Isolating tenants across node pools, namespaces, and network policies contains a node compromise. Shared namespaces and cluster-wide permissions would spread the blast radius." },
  { id:2182, domain:4, level:2, question:"Which is the best mitigation for the risk that an LLM reveals its confidential system prompt?", options:["Avoiding secrets in the system prompt and treating it as potentially exposable","Assuming the system prompt is confidential and never testing for leakage","Placing highly sensitive secrets in the system prompt but asking it to stay hidden","Increasing the model temperature so the system prompt becomes unpredictable"], correct:0, explanation:"System prompts can be extracted, so secrets must be kept out and the prompt treated as exposable. Placing secrets there and trusting concealment is a common, avoidable mistake." },
  { id:2183, domain:5, level:2, question:"Which practice best secures the CI/CD pipeline that deploys AI models to production?", options:["Signed commits, pipeline access controls, and artifact scanning before deployment","Allowing any developer to push directly to production without review gates","Sharing a single administrative credential among all pipeline stages","Disabling build logs so sensitive configuration is never written down"], correct:0, explanation:"Signed commits, access controls, and artifact scanning harden the deployment pipeline. Unrestricted pushes and shared admin credentials undermine pipeline integrity." },
  { id:2184, domain:6, level:2, question:"Why does the EU AI Act require transparency obligations for certain limited-risk AI systems like chatbots?", options:["To force disclosure of the model's full training dataset to the public","To mandate that all such systems be open-source and freely modifiable","So individuals know they are interacting with an AI rather than a human","To require that chatbots be hosted only within the European Union"], correct:2, explanation:"Transparency rules ensure people know they are dealing with AI, not a person. The Act does not require public training-data disclosure, open-sourcing, or EU-only hosting for chatbots." },
  { id:2185, domain:1, level:2, question:"Which statement best captures the security implication of the AI hallucination phenomenon?", options:["Hallucinations are eliminated entirely by increasing the training dataset size","Hallucinations only occur when the model runs on under-provisioned hardware","Hallucinations can produce convincing but false outputs that mislead downstream decisions","Hallucinations improve security by adding randomness to every model response"], correct:2, explanation:"Hallucinations yield plausible but false content that can mislead decisions and processes. They are not a hardware artifact, are not fully eliminated by more data, and do not aid security." },
  { id:2186, domain:2, level:2, question:"Which is the most appropriate way to handle customer data used in an AI feature to respect the right to erasure?", options:["Refusing all deletion requests because model training is inherently irreversible","Maintaining data lineage so records can be located and deleted or excluded on request","Storing customer data indefinitely since AI systems require large datasets","Encrypting the data and treating encryption as equivalent to deletion"], correct:1, explanation:"Data lineage enables locating and honoring erasure requests across storage and pipelines. Refusing deletion, indefinite retention, and equating encryption with deletion fail erasure duties." },
  { id:2187, domain:3, level:2, question:"Which benefit does hardware-based attestation add to a confidential AI workload?", options:["It guarantees the workload will scale automatically under increased demand","It compresses model weights to fit within a smaller enclave memory region","It verifies the enclave's identity and integrity before releasing secrets to it","It removes the requirement to authenticate users accessing the application"], correct:2, explanation:"Attestation cryptographically verifies enclave integrity before secrets are provisioned. It does not autoscale workloads, compress weights, or replace user authentication." },
  { id:2188, domain:4, level:3, question:"Why should an LLM-powered application enforce output length and content constraints on generated responses?", options:["To limit resource exhaustion and reduce exposure of sensitive or harmful content","To ensure the model always returns the single longest possible completion","To increase the model's temperature and thereby its creative variety","To guarantee that generated code compiles without any developer review"], correct:0, explanation:"Constraining output limits resource exhaustion and reduces leakage of harmful or sensitive content. It has nothing to do with maximizing length, temperature, or guaranteeing compilation." },
  { id:2189, domain:5, level:1, question:"What is the primary purpose of a guardrail model deployed in front of a primary LLM?", options:["To screen inputs and outputs for policy violations before they reach users","To increase the primary model's raw token generation throughput","To store conversation history for long-term analytics and reporting","To replace the primary model entirely during peak traffic periods"], correct:0, explanation:"A guardrail model screens inputs and outputs for policy violations. It is not a throughput booster, an analytics store, or a failover replacement for the main model." },
  { id:2190, domain:6, level:3, question:"Which challenge most complicates assigning liability when a third-party foundation model causes harm?", options:["Foundation models are always fully explainable, making causation trivial to prove","The multi-party supply chain obscures accountability among provider, deployer, and user","Liability law universally exempts all AI systems from any legal responsibility","Foundation models never process personal data, so privacy law never applies"], correct:1, explanation:"The layered supply chain among model provider, deployer, and user blurs accountability. Foundation models are not fully explainable, are not liability-exempt, and often do process personal data." },
  { id:2191, domain:1, level:2, question:"Which principle underlies 'privacy by design' for a cloud AI system?", options:["Adding privacy controls only after a regulator issues a formal complaint","Delegating all privacy decisions exclusively to the cloud provider","Collecting maximum data first and deciding what to protect afterward","Embedding privacy protections into the system architecture from the outset"], correct:3, explanation:"Privacy by design builds protections into the architecture from the start. Retrofitting after complaints or maximizing collection first contradicts the principle." },
  { id:2192, domain:2, level:2, question:"Which is the most effective safeguard against sensitive prompts being retained by a third-party AI provider?", options:["Assuming the provider deletes all prompts instantly with no configuration","Reviewing data-retention terms and opting out of training data usage where possible","Sending even more context so the provider has less incentive to retain it","Encrypting the prompt with a key the provider also fully controls"], correct:1, explanation:"Reviewing retention terms and opting out of training-data use limits provider retention. Assuming instant deletion or using a provider-controlled key gives no real assurance." },
  { id:2193, domain:3, level:2, question:"Which control best protects the Kubernetes API server, a high-value attack target?", options:["Exposing the API server publicly without authentication for easier automation","Strong authentication, RBAC, audit logging, and network-restricted access","Sharing the cluster-admin kubeconfig broadly across the engineering team","Disabling TLS on the API server to reduce certificate management overhead"], correct:1, explanation:"Authentication, RBAC, audit logging, and restricted access harden the API server. Public exposure, broad admin sharing, and disabling TLS would each critically weaken it." },
  { id:2194, domain:4, level:3, question:"Which approach best mitigates the risk of an LLM agent being manipulated into exfiltrating data via a tool call?", options:["Allowing the agent unrestricted outbound network access for maximum capability","Applying egress filtering and allow-lists on the tools and destinations the agent can reach","Trusting the agent to recognize exfiltration attempts without any constraints","Logging exfiltration only after the sensitive data has already left the boundary"], correct:1, explanation:"Egress filtering and destination allow-lists prevent an agent from sending data to unauthorized endpoints. Unrestricted access and blind trust invite exfiltration rather than preventing it." },
  { id:2195, domain:5, level:2, question:"Why is model versioning and rollback capability important for AI security operations?", options:["It removes the need to monitor the currently deployed model in production","It permanently prevents any future model from being poisoned or attacked","It compresses all historical models into a single immutable artifact","It enables quickly reverting to a known-good model if a new version is compromised"], correct:3, explanation:"Versioning and rollback let teams revert to a trusted model after a compromise. It does not prevent all attacks, compress models, or remove the need for ongoing monitoring." },
  { id:2196, domain:6, level:2, question:"Which activity is central to conducting an AI-specific risk assessment aligned with ISO/IEC 23894?", options:["Identifying, analyzing, and evaluating risks arising across the AI lifecycle","Selecting the cheapest cloud region to host the model's inference endpoint","Maximizing the number of parameters to improve benchmark performance","Outsourcing all accountability for AI outcomes to the model vendor"], correct:0, explanation:"ISO 23894-aligned assessment identifies, analyzes, and evaluates lifecycle AI risks. It is not about region cost, parameter counts, or shifting all accountability to a vendor." },
  { id:2197, domain:1, level:3, question:"Which trade-off is most important when choosing between a hosted foundation model API and a self-hosted open model?", options:["Self-hosting offers greater data control but shifts security burden to the customer","Hosted APIs always cost less and provide stronger security than self-hosting","Self-hosted models cannot be fine-tuned or customized for specific tasks","Hosted APIs give the customer full access to modify the underlying model weights"], correct:0, explanation:"Self-hosting increases data control but makes the customer responsible for securing the stack. Hosted APIs are not universally cheaper, and self-hosted models can indeed be fine-tuned." },
  { id:2198, domain:2, level:2, question:"Which is the best way to protect a vector database used for RAG from data poisoning?", options:["Allowing any user to write arbitrary documents into the shared vector index","Trusting all ingested content because embeddings obscure the original text","Disabling all access logging to reduce the storage footprint of the index","Validating, sanitizing, and controlling write access to the ingestion pipeline"], correct:3, explanation:"Validating content and controlling write access prevents poisoned documents entering the index. Open writes and blind trust in embeddings enable poisoning attacks." },
  { id:2199, domain:5, level:3, question:"When responding to a suspected model-extraction campaign against an inference API, which action is most appropriate first?", options:["Analyze query patterns, tighten rate limits, and enforce stronger authentication","Immediately shut down the entire cloud account to stop all activity at once","Publicly disclose the model architecture to reduce the attacker's incentive","Ignore the activity since extraction attacks cannot succeed against large models"], correct:0, explanation:"Analyzing query patterns and tightening rate limits and authentication contains extraction while preserving service. A full account shutdown is disproportionate, and disclosure or ignoring it makes matters worse." },
  { id:2200, domain:6, level:2, question:"Why should organizations maintain human oversight for high-impact automated AI decisions under emerging regulation?", options:["To ensure a person can review, contest, or override consequential AI outcomes","To increase the raw speed at which decisions are rendered to end users","To remove the organization's accountability by deferring entirely to the model","To eliminate the need to document how the AI system reaches its decisions"], correct:0, explanation:"Human oversight lets people review, contest, and override high-impact AI decisions, a core regulatory expectation. It does not speed decisions, remove accountability, or eliminate documentation duties." },
  { id:2201, domain:5, level:2, question:"Which monitoring signal most directly indicates a possible prompt-injection campaign against a production LLM service?", options:["A gradual decrease in average response latency across all tenant workloads","Clusters of inputs attempting to override system instructions or extract prompts","Steady growth in the number of authenticated users onboarding each week","A reduction in the total number of tokens billed during off-peak hours"], correct:1, explanation:"Inputs trying to override instructions or reveal the system prompt signal injection attempts. Falling latency or fewer billed tokens are performance metrics unrelated to injection." },
  { id:2202, domain:6, level:2, question:"Which practice best supports demonstrating accountability for an AI system during a regulatory audit?", options:["Deleting model documentation after deployment to minimize discoverable records","Relying on the cloud provider to answer all questions about model behavior","Keeping no logs so that no sensitive processing can ever be reconstructed","Maintaining model cards, risk assessments, and decision-logging throughout the lifecycle"], correct:3, explanation:"Model cards, risk assessments, and decision logs evidence accountability to auditors. Deleting documentation or keeping no logs undermines the ability to demonstrate governance." },
  { id:2203, domain:1, level:1, question:"What does the term MLOps most accurately describe?", options:["A regulation governing the cross-border transfer of AI training datasets","A hardware standard defining the interconnect between GPU accelerator cards","A pricing tier offered exclusively for large-scale distributed training jobs","Practices for building, deploying, monitoring, and governing ML models in production"], correct:3, explanation:"MLOps covers the operational lifecycle of ML models from build to monitoring. It is not a hardware standard, a pricing tier, or a data-transfer regulation." },
  { id:2204, domain:2, level:2, question:"Which is the strongest safeguard against confidential data leaking through model outputs in a shared AI service?", options:["Assuming the provider automatically scrubs all sensitive data from responses","Output filtering combined with data-loss-prevention checks on generated content","Increasing response verbosity so users can spot any leaked data themselves","Storing every generated response indefinitely for future audit convenience"], correct:1, explanation:"Output filtering plus DLP checks catch sensitive content before it reaches users. Assuming automatic scrubbing or increasing verbosity does not reliably prevent leakage." },
  { id:2205, domain:3, level:3, question:"Why is workload attestation valuable when deploying AI inference within confidential computing enclaves?", options:["It automatically encrypts network traffic between all microservices in the mesh","It guarantees the inference workload will never exceed its memory allocation","It verifies enclave integrity before decryption keys are released to the workload","It removes the requirement to authenticate the end users of the application"], correct:2, explanation:"Attestation confirms the enclave is genuine and unmodified before keys are released. It does not encrypt mesh traffic, cap memory, or replace user authentication." },
  { id:2206, domain:4, level:2, question:"Which control best limits the damage if an LLM chatbot is tricked into generating a malicious URL?", options:["Allowing the client to auto-open any URL the model generates for user convenience","Validating and rewriting or blocking model-generated links before display","Increasing the temperature so generated URLs become harder to predict","Trusting the model to only ever produce links to reputable known domains"], correct:2, explanation:"Validating and sanitizing model-generated links before display prevents malicious redirects. Auto-opening links or trusting the model to self-restrict leaves users exposed." },
  { id:2207, domain:5, level:2, question:"Which is a key operational reason to isolate the network egress of an autonomous LLM agent?", options:["Egress isolation increases the model's reasoning accuracy on complex tasks","Egress isolation reduces the electricity consumed by the inference cluster","Egress isolation eliminates the need to authenticate the agent's API calls","Egress isolation prevents an exploited agent from exfiltrating data to arbitrary hosts"], correct:3, explanation:"Restricting egress stops a compromised agent from sending data to unauthorized destinations. It does not affect reasoning accuracy, power draw, or authentication requirements." },
  { id:2208, domain:6, level:2, question:"Which factor makes cross-border data transfer especially complex for cloud AI training?", options:["Training always requires data to be duplicated into every available cloud region","Model weights are inherently classified as export-controlled munitions everywhere","AI models cannot be trained on data that is encrypted during transit at all","Differing jurisdictional laws govern personal data, creating conflicting transfer obligations"], correct:3, explanation:"Divergent national data-protection laws create conflicting transfer obligations for training data. Training does not require duplication everywhere, nor is all data export-controlled." },
  { id:2209, domain:1, level:2, question:"Which best describes the concept of trustworthy AI as promoted by governance frameworks?", options:["AI that operates entirely without any form of human involvement or review","AI that always achieves the highest accuracy regardless of any other concern","AI whose model weights are kept fully secret from every external party","AI that is valid, reliable, safe, secure, accountable, transparent, and fair"], correct:3, explanation:"Trustworthy AI encompasses validity, safety, security, accountability, transparency, and fairness. Chasing accuracy alone or removing human involvement contradicts the concept." },
  { id:2210, domain:2, level:2, question:"Which technique best reduces re-identification risk when preparing a dataset for model training?", options:["Publishing the raw dataset so the community can help find quality issues","Retaining all direct identifiers to preserve the maximum analytical value","Applying anonymization or pseudonymization with k-anonymity or similar controls","Storing the dataset only in encrypted form and treating that as anonymization"], correct:2, explanation:"Anonymization or pseudonymization with k-anonymity reduces re-identification risk. Encryption is not anonymization, and retaining direct identifiers keeps records identifiable." },
  { id:2211, domain:3, level:2, question:"Which is a primary security advantage of immutable infrastructure in cloud-native deployments?", options:["It permanently removes the need for any vulnerability scanning of images","Replacing rather than modifying instances reduces configuration drift and persistence","It allows administrators to patch running servers directly in production","It guarantees that deployed workloads can never be targeted by any attacker"], correct:1, explanation:"Immutable infrastructure replaces instances instead of patching them, curbing drift and attacker persistence. It does not remove scanning needs or make workloads unattackable." },
  { id:2212, domain:4, level:3, question:"Why is context-window management a security consideration in LLM applications?", options:["Reducing the context window guarantees the model cannot be jailbroken","A larger context window automatically encrypts all conversation history","Context windows determine the physical location where prompts are stored","Injected or malicious content persisting in context can influence later responses"], correct:3, explanation:"Malicious content lingering in the context can steer subsequent outputs, so context must be managed. Window size does not encrypt history, set storage location, or prevent jailbreaks." },
  { id:2213, domain:5, level:2, question:"Which practice best hardens the MLOps model registry against unauthorized tampering?", options:["Role-based access control, artifact signing, and immutable version retention","Publishing registry credentials in the shared team wiki for convenience","Disabling version history so old artifacts cannot be examined by attackers","Granting all data scientists write access to production model artifacts"], correct:0, explanation:"RBAC, signing, and immutable versions protect the registry from tampering. Broad write access, shared credentials, or removing history all weaken registry integrity." },
  { id:2214, domain:6, level:2, question:"Under a risk-based AI regulatory approach, obligations generally scale with what?", options:["The total number of parameters contained within the deployed model","The potential impact and severity of harm the AI system could cause","The monthly cloud infrastructure cost of hosting the AI workload","The programming language used to implement the model's inference code"], correct:1, explanation:"Risk-based regulation scales obligations to the severity of potential harm. Parameter count, hosting cost, and implementation language do not determine regulatory tier." },
  { id:2215, domain:1, level:1, question:"What is the primary purpose of a model card in AI governance?", options:["Documenting a model's intended use, limitations, performance, and ethical considerations","Storing the encrypted weights of the model for secure long-term archival","Serving as the billing invoice for inference usage across cloud regions as a general practice","Providing the physical wiring diagram for the model's training hardware"], correct:0, explanation:"A model card documents intended use, limitations, and performance for transparency. It is not a weight archive, a billing invoice, or a hardware diagram." },
  { id:2216, domain:2, level:2, question:"Which approach best addresses privacy when logging prompts sent to an LLM for debugging?", options:["Logging complete raw prompts including any personal data for full fidelity","Redacting or masking sensitive fields and applying strict retention limits on logs","Sharing debug logs broadly across teams to accelerate issue resolution","Disabling encryption on log storage to make searching the logs faster"], correct:1, explanation:"Redacting sensitive fields and limiting retention protects privacy while enabling debugging. Logging raw PII, broad sharing, or unencrypted storage each raises privacy risk." },
  { id:2217, domain:3, level:3, question:"Which container-security measure most directly reduces the risk from a vulnerable base image dependency?", options:["Running the container with additional Linux capabilities for flexibility","Deploying more replicas of the container to improve overall availability","Storing container images in a publicly readable registry for easy access","Continuous image scanning with automated rebuilds when fixes become available"], correct:3, explanation:"Continuous scanning plus automated rebuilds patch vulnerable dependencies quickly. Adding capabilities, scaling replicas, or public registries do not remediate the vulnerability." },
  { id:2218, domain:4, level:2, question:"Which is the best mitigation for excessive agency in an LLM-driven automation workflow?", options:["Removing all audit logging so the agent operates with minimal overhead","Granting the agent broad standing privileges so it never blocks on approvals","Allowing the agent to modify its own permission boundaries when needed","Scoping the agent's permissions and requiring confirmation for consequential actions"], correct:3, explanation:"Scoping permissions and requiring confirmation for high-impact actions curbs excessive agency. Broad standing privileges or self-modifying boundaries expand the risk instead." },
  { id:2219, domain:5, level:2, question:"Why should an organization maintain an inventory of all AI models and their data sources in use?", options:["Because visibility enables risk assessment, incident response, and compliance tracking","Because it reduces the cloud storage cost of hosting the models themselves","Because inventories automatically remediate any vulnerabilities they discover","Because it guarantees that shadow AI usage can never occur in the enterprise"], correct:0, explanation:"An AI inventory provides visibility needed for risk assessment, response, and compliance. It does not auto-remediate, reduce storage cost, or by itself eliminate shadow AI." },
  { id:2220, domain:6, level:3, question:"Which challenge complicates applying the GDPR right to explanation to complex AI decisions?", options:["Deep models can be opaque, making meaningful explanations of decisions difficult","GDPR explicitly exempts all automated decision-making from any explanation duty","Explanations are only required for decisions made entirely by human reviewers","AI decisions never involve personal data and so fall outside GDPR entirely"], correct:0, explanation:"Opaque deep models make meaningful, individualized explanations hard to produce. GDPR does not exempt automated decisions, and such decisions frequently involve personal data." },
  { id:2221, domain:1, level:2, question:"Which statement best characterizes federated learning from a cloud security perspective?", options:["It trains models across distributed data sources without centralizing the raw data","It requires uploading all raw training data to a single central cloud server","It eliminates the need for any privacy controls because data stays encrypted","It guarantees that the resulting model cannot leak any training information"], correct:0, explanation:"Federated learning trains across distributed data without centralizing raw records. It still needs privacy controls, since model updates can leak information." },
  { id:2222, domain:2, level:2, question:"Which is the best way to protect against sensitive data being embedded and stored in a vector index without authorization?", options:["Classifying source data and applying ingestion-time policies before embedding it","Assuming vector embeddings are anonymous and require no data classification","Trusting downstream apps to filter results rather than controlling ingestion","Allowing every application to write documents into the shared vector store freely"], correct:0, explanation:"Classifying data and enforcing ingestion-time policy prevents unauthorized embedding of sensitive content. Treating embeddings as anonymous or relying only on downstream filtering fails." },
  { id:2223, domain:3, level:1, question:"What is the primary purpose of a CWPP agent running on a cloud VM?", options:["Managing the DNS zone records for the organization's public domains as a general practice","Negotiating discounted compute pricing with the cloud service provider","Detecting threats, vulnerabilities, and misconfigurations at the workload runtime level","Rotating the TLS certificates used by the external load balancer fleet"], correct:2, explanation:"A CWPP agent provides runtime threat and vulnerability protection for workloads. Pricing negotiation, DNS, and certificate rotation are outside its scope." },
  { id:2224, domain:4, level:2, question:"Which measure best defends an LLM application against denial-of-wallet attacks that inflate inference costs?", options:["Rate limiting, per-user budgets, and anomaly detection on request volume","Removing all usage quotas so genuine users never encounter throttling","Allowing anonymous unlimited requests to maximize product engagement","Increasing the per-request token limit so fewer requests are needed"], correct:0, explanation:"Rate limits, budgets, and anomaly detection contain runaway inference costs. Removing quotas or allowing unlimited anonymous requests enables denial-of-wallet abuse." },
  { id:2225, domain:5, level:2, question:"Which is the most effective way to detect model drift affecting a production classifier's security posture?", options:["Assuming a validated model will perform identically forever after deployment","Disabling monitoring once the model passes its initial acceptance testing","Retraining the model daily regardless of whether any drift has occurred","Continuously comparing live prediction distributions against known baselines"], correct:3, explanation:"Comparing live distributions to baselines detects drift as it emerges. Assuming permanent stability or disabling monitoring leaves drift undetected." },
  { id:2226, domain:6, level:2, question:"Which is a key reason data provenance matters for AI compliance obligations?", options:["Provenance automatically anonymizes any personal data used during training","Provenance guarantees the model will produce unbiased predictions every time","It removes the need to obtain consent for processing personal information","It evidences lawful basis and traceability of data used to train the model"], correct:3, explanation:"Provenance evidences lawful basis and traceability required for compliance. It does not auto-anonymize data, guarantee fairness, or waive consent requirements." },
  { id:2227, domain:1, level:2, question:"Which best describes the shared responsibility consideration for a customer fine-tuning a provider's foundation model?", options:["The provider becomes solely responsible for any bias introduced by customer data","The customer is responsible for the security and quality of the fine-tuning data","Fine-tuning transfers all model IP ownership permanently to the customer","The provider must review and approve every fine-tuning dataset before use"], correct:1, explanation:"The customer owns responsibility for the security and quality of data they supply for fine-tuning. The provider does not automatically absorb bias from customer data." },
  { id:2228, domain:2, level:2, question:"Which control most directly supports the principle of data minimization in an AI feature?", options:["Collecting only the data necessary for the specific, defined AI purpose","Retaining all collected data indefinitely to support future model versions","Duplicating datasets across regions to maximize training throughput","Collecting as much data as possible now in case it proves useful later"], correct:0, explanation:"Data minimization means collecting only what the defined purpose requires. Collecting or retaining everything, or duplicating widely, contradicts minimization." },
  { id:2229, domain:3, level:3, question:"Why does secrets sprawl pose a heightened risk in cloud-native microservice architectures?", options:["Microservices are physically isolated, so secrets can never be intercepted","Many services each need credentials, multiplying places secrets can be exposed","Secrets in microservices are automatically rotated by the container runtime","Microservice secrets are always stored only in memory and never persisted"], correct:1, explanation:"Numerous services each holding credentials multiply the exposure surface for secrets. Microservices are not physically isolated, and runtimes do not auto-rotate secrets by default." },
  { id:2230, domain:4, level:2, question:"Which is the best defense against an attacker embedding hidden instructions in a document processed by a RAG system?", options:["Trusting retrieved documents fully because they come from an internal store","Disabling retrieval logging to prevent attackers from studying the pipeline","Increasing the model temperature so hidden instructions are less likely followed","Treating retrieved content as untrusted data and constraining its influence on actions"], correct:3, explanation:"Treating retrieved content as untrusted and limiting its ability to trigger actions defends against embedded instructions. Trusting internal documents blindly enables indirect injection." },
  { id:2231, domain:5, level:2, question:"Which capability most improves incident response for an AI-driven cloud application?", options:["Storing logs without any timestamps to simplify the log schema design","Deleting all logs after 24 hours to minimize the storage footprint","Correlated logging of prompts, model versions, tool calls, and user identity","Logging only errors while discarding all successful interaction records"], correct:2, explanation:"Correlated logging across prompts, versions, tools, and identity accelerates investigation. Dropping timestamps, short retention, or logging only errors hampers response." },
  { id:2232, domain:6, level:2, question:"Which practice best supports responsible AI transparency toward affected individuals?", options:["Keeping the existence of automated decisioning entirely undisclosed to users","Disclosing when AI is used and offering meaningful information about decisions","Providing no channel for individuals to question or appeal AI decisions","Concealing which data categories the model uses to protect trade secrets"], correct:1, explanation:"Disclosing AI use and providing meaningful decision information supports transparency. Concealment or offering no appeal channel undermines responsible AI principles." },
  { id:2233, domain:1, level:2, question:"Which best explains why guardrails should be applied to both inputs and outputs of an LLM?", options:["Only input guardrails are needed since outputs are always inherently safe","Input and output guardrails together catch malicious prompts and unsafe generations","Only output guardrails matter because inputs cannot influence model behavior","Guardrails on either side make the model mathematically impossible to jailbreak"], correct:1, explanation:"Bidirectional guardrails catch both malicious inputs and unsafe outputs. Inputs clearly influence behavior, and no guardrail makes a model provably unjailbreakable." },
  { id:2234, domain:2, level:2, question:"Which is the most appropriate control for protecting model checkpoints stored in cloud object storage?", options:["Encryption at rest, least-privilege access policies, and versioning on the bucket","Relying on obscure bucket names to keep the checkpoints hidden from attackers","Storing checkpoints unencrypted to reduce the compute overhead of training","Making checkpoint buckets public so distributed training nodes can reach them"], correct:0, explanation:"Encryption, least-privilege policies, and versioning protect stored checkpoints. Public buckets, name obscurity, or unencrypted storage leave valuable artifacts exposed." },
  { id:2235, domain:3, level:2, question:"Which is a core benefit of using short-lived certificates for workload identity in a service mesh?", options:["They permanently prevent any certificate from ever being compromised","Short-lived certificates eliminate the need for mutual TLS between services","They remove the requirement to authorize service-to-service API calls","Frequent automatic rotation limits the window a stolen certificate is useful"], correct:3, explanation:"Short-lived, auto-rotated certificates shrink the useful window of a stolen credential. They complement, not replace, mTLS and authorization, and cannot prevent all compromise." },
  { id:2236, domain:4, level:3, question:"Why is server-side enforcement of authorization critical even when an LLM agent performs actions on a user's behalf?", options:["Because the agent could be manipulated into requesting actions beyond the user's rights","Because client-side checks in the agent are transparent and cannot be bypassed","Because the LLM's own reasoning is sufficient to enforce all access controls","Because authorization is unnecessary once the user has authenticated once"], correct:0, explanation:"A manipulated agent may request over-privileged actions, so the backend must enforce authorization. The model's reasoning and client-side checks cannot be trusted as the control." },
  { id:2237, domain:5, level:2, question:"Which is the best approach to managing vulnerabilities in third-party model dependencies?", options:["Ignoring model dependencies since only application code carries real risk","Assuming popular open-source models are inherently free of vulnerabilities","Scanning dependencies against an SBOM and monitoring for new disclosures","Freezing all versions permanently so no dependency ever changes again"], correct:2, explanation:"Scanning against an SBOM and monitoring disclosures keeps model dependencies patched. Ignoring them or assuming popularity equals safety leaves known flaws unaddressed." },
  { id:2238, domain:6, level:2, question:"Which is a primary compliance concern when using personal data found in prompts for model improvement?", options:["Personal data in prompts is exempt from privacy regulation by definition","Prompt data is always anonymous and therefore never triggers privacy law","Using prompts for training automatically satisfies all transparency duties","Processing prompt data for training may exceed the original consent or purpose"], correct:3, explanation:"Reusing prompt data for training can breach the original purpose or consent basis. Prompt data is not inherently anonymous, nor exempt from privacy law." },
  { id:2239, domain:1, level:2, question:"Which best characterizes the security relevance of the AI supply chain for an enterprise consumer?", options:["Only the final application code matters; upstream components carry no risk","Compromised base models, datasets, or libraries can propagate risk downstream","Foundation models cannot carry any embedded risk once they are fine-tuned","Supply-chain risk applies only to physical hardware, never to AI artifacts"], correct:1, explanation:"Compromised upstream models, data, or libraries propagate risk into downstream applications. Upstream components clearly carry risk, and fine-tuning does not neutralize it." },
  { id:2240, domain:2, level:2, question:"Which technique best prevents a large language model from memorizing and reproducing rare sensitive records?", options:["Training for as many epochs as possible to fully fit the entire dataset","Applying differential privacy and de-duplicating rare records before training","Removing all validation so training completes faster and cheaper overall","Increasing the model size so it can store more of the training corpus"], correct:1, explanation:"Differential privacy and de-duplication reduce memorization of rare records. More epochs or larger models tend to increase memorization, and removing validation helps nothing." },
  { id:2241, domain:3, level:2, question:"Which practice most reduces the attack surface of a serverless function's execution role?", options:["Granting the function full administrative access to simplify future changes","Reusing one broad role across many unrelated functions for consistency","Attaching every available managed policy so nothing is ever blocked","Scoping the role to only the specific resources and actions the function needs"], correct:3, explanation:"Least-privilege scoping to only needed resources shrinks the function's attack surface. Admin access, shared broad roles, or all policies expand it dramatically." },
  { id:2242, domain:4, level:2, question:"Which is the best way to handle an LLM response that will be rendered as HTML in a browser?", options:["Rendering the raw model output directly to preserve formatting fidelity","Trusting the model never to produce script tags or event-handler attributes","Encoding and sanitizing the output to neutralize any injected active content","Disabling the browser's content security policy to allow richer responses"], correct:2, explanation:"Encoding and sanitizing output prevents cross-site scripting from model-generated HTML. Rendering raw output or trusting the model to avoid scripts invites XSS." },
  { id:2243, domain:4, level:1, question:"placeholder", options:["a","b","c","d"], correct:0, explanation:"placeholder" },
  { id:2244, domain:5, level:2, question:"Which practice best supports secure secret injection into containerized AI workloads at runtime?", options:["Passing secrets as plaintext command-line arguments visible in the process list","Hardcoding API keys into the container image so deployment is fully self-contained","Retrieving secrets from a managed vault at startup rather than baking them into images","Committing secrets into the Helm chart so they are versioned with the deployment"], correct:2, explanation:"Fetching secrets from a managed vault at runtime avoids embedding them in artifacts. Hardcoding in images, CLI args, or Helm charts persists and exposes the secrets." },
  { id:2245, domain:6, level:2, question:"Which is a defining obligation the EU AI Act places on providers of general-purpose AI models?", options:["A total ban on offering any general-purpose model within the European market","A requirement to open-source the full model weights to all European citizens","Technical documentation, transparency, and, for systemic-risk models, added obligations","A prohibition on any commercial licensing of general-purpose model outputs"], correct:2, explanation:"GPAI providers must supply documentation and transparency, with extra duties for systemic-risk models. The Act does not ban all such models or force open-sourcing of weights." },
  { id:2246, domain:1, level:2, question:"Which best explains the purpose of an AI risk register within an organization's governance program?", options:["Recording the per-token inference cost of each model across regions","Storing the encrypted training datasets used by every deployed model","Centrally tracking identified AI risks, owners, controls, and mitigation status","Listing the marketing claims made about each AI product to customers"], correct:2, explanation:"A risk register tracks AI risks, owners, controls, and mitigation status centrally. It is not a dataset store, cost ledger, or marketing-claims list." },
  { id:2247, domain:2, level:2, question:"Which is the most appropriate control to prevent data leakage between tenants in a shared RAG service?", options:["Storing all tenants' documents in one unpartitioned index for efficiency","Relying on the model to refuse to reveal another tenant's information","Strong tenant isolation with per-tenant partitions and retrieval-time authorization","Encrypting the whole index with one shared key across every tenant"], correct:2, explanation:"Per-tenant partitions plus retrieval-time authorization prevent cross-tenant leakage. A shared index, model-based refusal, or one shared key do not enforce isolation." },
  { id:2248, domain:3, level:3, question:"Why is runtime detection important even in a well-configured cloud-native environment with strong CSPM?", options:["CSPM findings automatically block all runtime exploitation without any agents","Runtime detection is unnecessary once configuration posture is fully compliant","Configuration compliance alone cannot catch active exploitation or in-memory attacks","Runtime detection only duplicates what infrastructure-as-code scanning provides"], correct:2, explanation:"Posture compliance does not catch live exploitation or in-memory threats, which need runtime detection. CSPM does not block runtime attacks, and it is not redundant with IaC scanning." },
  { id:2249, domain:4, level:2, question:"Which is the best mitigation for the risk that an LLM plugin returns malicious data to the model?", options:["Trusting all plugin responses because plugins are vetted before installation","Validating and sanitizing plugin responses before the model acts on them","Increasing the model temperature so malicious data is less influential","Passing plugin output straight into the next tool call without inspection"], correct:1, explanation:"Validating and sanitizing plugin output prevents malicious data from steering the model. Trusting vetted plugins blindly or piping output onward invites compromise." },
  { id:2250, domain:5, level:2, question:"Which practice best supports continuous compliance monitoring for AI workloads in the cloud?", options:["Annual manual audits as the sole mechanism for verifying compliance state","Automated policy-as-code checks that continuously evaluate configuration and usage","Assuming compliance is maintained automatically after the initial deployment","Disabling monitoring to avoid generating findings that require remediation"], correct:1, explanation:"Policy-as-code checks continuously evaluate compliance as environments change. Annual-only audits, assumptions, or disabled monitoring leave gaps between reviews." },
  { id:2251, domain:6, level:2, question:"Which is a key privacy consideration when using customer conversations to fine-tune a model?", options:["Conversations become fully anonymous the moment they enter a training pipeline","Obtaining a lawful basis and de-identifying data before including it in training","Fine-tuning on conversations never involves any personal data by definition","Fine-tuning removes all obligation to honor future data-subject erasure requests"], correct:1, explanation:"A lawful basis and de-identification are needed before using conversations for training. Conversations are not automatically anonymous, and erasure obligations still apply." },
  { id:2252, domain:1, level:2, question:"Which statement best reflects the concept of least privilege applied to AI agent tool access?", options:["Agents should hold every tool permission upfront to avoid future blocking","Tool permissions are irrelevant once the agent authenticates successfully","Agents work best when they can escalate their own privileges autonomously","An agent should be granted only the specific tools required for its current task"], correct:3, explanation:"Least privilege grants the agent only the tools its task requires. Broad upfront permissions or self-escalation contradict the principle and widen the blast radius." },
  { id:2253, domain:2, level:2, question:"Which is the strongest safeguard for keys used to encrypt sensitive AI training data?", options:["Embedding the keys directly in the training scripts for reproducibility","Storing the encryption keys alongside the ciphertext in the same storage bucket","Managing keys in a dedicated KMS or HSM with strict access controls and rotation","Sharing a single static key across all datasets to simplify decryption"], correct:2, explanation:"A KMS or HSM with access controls and rotation protects encryption keys. Co-locating keys with ciphertext, embedding them in scripts, or reusing one static key defeats the protection." },
  { id:2254, domain:3, level:2, question:"Which is a primary security benefit of a service mesh's mutual TLS between microservices?", options:["It eliminates the need for any authorization decisions within the mesh","It authenticates both endpoints and encrypts service-to-service traffic automatically","It guarantees that application-layer input validation is no longer required","It physically isolates each microservice onto separate dedicated hardware"], correct:1, explanation:"Mesh mTLS mutually authenticates services and encrypts their traffic transparently. It does not remove authorization or input-validation needs, nor provide physical isolation." },
  { id:2255, domain:4, level:2, question:"Which is the best way to reduce the risk of an LLM disclosing another user's data in a multi-user app?", options:["Sharing one conversation context across all users to improve response quality","Enforcing per-user data isolation and scoping context strictly to the current user","Storing all users' data in a single prompt so the model has full context","Trusting the model to keep each user's data separate without any enforcement"], correct:1, explanation:"Per-user isolation and strict context scoping prevent cross-user disclosure. Sharing context or trusting the model to self-segregate risks leaking one user's data to another." },
  { id:2256, domain:5, level:2, question:"Which is the most effective first step when onboarding a new third-party AI model into production?", options:["Assuming it is safe because it is widely used across the industry","Deploying it directly to production to gather real user feedback quickly","Granting it broad data access immediately to evaluate its full capabilities","Assessing its provenance, license, security posture, and known vulnerabilities"], correct:3, explanation:"Assessing provenance, license, and security posture before deployment manages supply-chain risk. Deploying directly or granting broad access first skips essential due diligence." },
  { id:2257, domain:6, level:3, question:"Which factor most complicates honoring a data-subject erasure request after a model has been trained?", options:["Erasure requests are legally inapplicable to any machine learning system","Models never contain any trace of individual training records after training","Trained model weights may retain information that is difficult to selectively remove","Erasure only applies to structured databases and never to any AI models"], correct:2, explanation:"Weights can retain learned information that is hard to selectively unlearn, complicating erasure. Erasure duties do apply to AI, and models can retain traces of records." },
  { id:2258, domain:1, level:2, question:"Which best describes why confidential computing is relevant to multi-party AI collaboration?", options:["It lets parties jointly compute on combined data without exposing raw inputs to each other","It removes the need for any contractual data-sharing agreement between parties","It guarantees that the resulting model will be free of any bias or error","It automatically anonymizes all inputs before any computation takes place"], correct:0, explanation:"Confidential computing enables joint computation while keeping each party's raw data protected. It does not replace contracts, guarantee fairness, or auto-anonymize inputs." },
  { id:2259, domain:2, level:2, question:"Which control best mitigates the risk of prompts containing regulated data being retained by a SaaS AI vendor?", options:["Assuming the vendor deletes all prompt data instantly with no configuration needed","Reviewing and negotiating data-processing and retention terms in the vendor contract","Sending regulated data in larger batches so it is harder for the vendor to isolate","Encrypting prompts with a key that the vendor also fully controls and manages"], correct:1, explanation:"Negotiating data-processing and retention terms governs how the vendor handles regulated data. Assuming instant deletion or using a vendor-held key offers no real assurance." },
  { id:2260, domain:3, level:2, question:"Which practice best protects the Kubernetes secrets stored in etcd?", options:["Storing all secrets as plaintext in etcd to simplify troubleshooting access","Disabling audit logging on secret access to reduce control-plane noise","Granting every namespace read access to all cluster secrets for convenience","Enabling encryption at rest for etcd and restricting API access to secrets"], correct:3, explanation:"Encrypting etcd at rest and tightly restricting secret access protects Kubernetes secrets. Plaintext storage, broad read access, or disabling audit logging weaken protection." },
  { id:2261, domain:4, level:3, question:"Why is limiting an LLM's ability to make outbound network requests an important application control?", options:["Outbound limits improve the grammatical quality of the model's written responses","Restricting outbound calls prevents a manipulated model from reaching internal or malicious endpoints","Outbound limits reduce the electricity consumed by each inference request as a general practice","Outbound limits guarantee the model can never be affected by prompt injection"], correct:1, explanation:"Restricting outbound calls stops a manipulated model from reaching internal services or attacker endpoints. It does not affect writing quality, power use, or immunity to injection." },
  { id:2262, domain:5, level:2, question:"Which is the best practice for handling model artifacts across development, staging, and production?", options:["Rebuilding the model separately in each environment to guarantee freshness","Promoting a single signed, immutable artifact through the environments unchanged","Sharing one mutable artifact tag that each environment overwrites in place","Allowing production to pull unsigned artifacts directly from developer laptops"], correct:1, explanation:"Promoting one signed, immutable artifact ensures what was tested is what runs in production. Rebuilding per environment, unsigned pulls, or mutable tags break integrity assurances." },
  { id:2263, domain:6, level:2, question:"Which is a core requirement for high-risk AI systems under the EU AI Act regarding data?", options:["High-risk systems must be trained only on data collected within one member state","High-risk systems are exempt from any data-quality obligations under the Act","Training, validation, and testing data must meet quality and governance criteria","All training data for high-risk systems must be made publicly downloadable"], correct:2, explanation:"The Act requires data governance and quality for training, validation, and testing datasets. It neither restricts data to one state nor mandates public release, and there is no exemption." },
  { id:2264, domain:1, level:1, question:"What does SASE primarily aim to converge?", options:["Database storage and compute into one consolidated managed service tier","Model training and inference workloads onto a single shared GPU cluster","Networking and network-security functions delivered together from the cloud edge","Physical datacenter cooling and power management into a unified controller"], correct:2, explanation:"SASE converges networking and security functions at the cloud edge. It has nothing to do with GPU clusters, database consolidation, or datacenter facilities." },
  { id:2265, domain:2, level:2, question:"Which approach best protects sensitive data during the feature-engineering stage of an ML pipeline?", options:["Applying access controls, encryption, and masking to intermediate feature datasets","Sharing feature datasets publicly so the whole team can iterate quickly","Removing all access controls so pipelines never fail due to permissions","Copying raw sensitive data to every engineer's local workstation for speed"], correct:0, explanation:"Access controls, encryption, and masking protect intermediate feature data. Copying raw data locally, public sharing, or removing controls all expose sensitive information." },
  { id:2266, domain:3, level:2, question:"Which is the most effective way to prevent privilege escalation through over-permissioned cloud IAM roles?", options:["Assigning wildcard permissions so no legitimate action is ever denied","Reusing one powerful role across every workload to simplify management","Granting temporary admin access that is never subsequently revoked or reviewed","Regularly reviewing entitlements and enforcing least privilege with CIEM tooling"], correct:3, explanation:"Regular entitlement reviews and least-privilege enforcement via CIEM curb escalation paths. Wildcards, shared powerful roles, or unrevoked admin access enable escalation." },
  { id:2267, domain:4, level:2, question:"Which is the best mitigation against a jailbreak that coaxes an LLM into producing disallowed content?", options:["Relying solely on the base model's built-in refusals with no additional layers","Assuming a strong system prompt makes jailbreaks completely impossible","Layered defenses: input screening, output moderation, and continuous red-teaming","Increasing the temperature so disallowed content is generated less coherently"], correct:2, explanation:"Layered input screening, output moderation, and red-teaming provide defense in depth against jailbreaks. Relying on built-in refusals or a system prompt alone is insufficient." },
  { id:2268, domain:5, level:3, question:"When investigating suspected training-data poisoning, which action is the most appropriate early step?", options:["Immediately deleting the entire dataset before any analysis can be performed","Ignoring the concern because poisoning cannot affect large modern models","Retraining the model on the same data to see if the problem resolves itself","Auditing data provenance and comparing recent ingests against trusted baselines"], correct:3, explanation:"Auditing provenance and comparing ingests to baselines helps confirm and localize poisoning. Deleting everything first destroys evidence, and retraining on suspect data repeats the problem." },
  { id:2269, domain:6, level:2, question:"Which is a primary purpose of algorithmic impact assessments in AI governance?", options:["Evaluating potential harms and disparate impacts before deploying an AI system","Optimizing the inference cost of the model across different cloud regions","Benchmarking model accuracy against competing vendors' published leaderboards","Certifying the model as permanently compliant with all future regulations"], correct:0, explanation:"Impact assessments evaluate potential harms and disparate impacts before deployment. They are not accuracy benchmarks, cost optimizers, or permanent compliance certificates." },
  { id:2270, domain:1, level:2, question:"Which best describes the relationship between CNAPP and its component capabilities?", options:["CNAPP is solely a network firewall that filters traffic at the perimeter","CNAPP is a narrower tool that only scans container images before deployment","CNAPP replaces the need for any identity or access management in the cloud","CNAPP integrates CSPM, CWPP, CIEM, and often IaC scanning into one platform"], correct:3, explanation:"CNAPP unifies CSPM, CWPP, CIEM, and IaC scanning into one platform. It is broader than image scanning and does not replace IAM or act merely as a firewall." },
  { id:2271, domain:2, level:2, question:"Which is the best way to protect data confidentiality when multiple teams share a single vector database?", options:["Namespacing per team with access controls and query-time authorization checks","Assuming embeddings cannot be reversed so isolation is entirely unnecessary","Storing all teams' vectors in one namespace and hoping queries stay scoped","Granting all teams read access to every namespace to simplify collaboration"], correct:0, explanation:"Per-team namespaces with access controls and query-time checks preserve confidentiality. Shared namespaces, assuming irreversibility, or broad read access all risk leakage." },
  { id:2272, domain:3, level:2, question:"Which is a key security reason to scan infrastructure-as-code before applying it?", options:["IaC scanning guarantees the deployment will never experience any downtime","IaC scanning automatically negotiates cheaper pricing with the cloud provider","IaC scanning replaces the need for runtime workload protection entirely","IaC scanning catches insecure defaults and misconfigurations before provisioning"], correct:3, explanation:"Scanning IaC catches insecure defaults before resources exist. It does not guarantee uptime, affect pricing, or replace runtime protection." },
  { id:2273, domain:4, level:2, question:"Which is the best mitigation for insecure output handling in an LLM-backed API?", options:["Passing model output directly into database queries to preserve flexibility","Rendering model output as executable code without any review to save time","Treating output as untrusted and validating or encoding it before downstream use","Assuming model output is always safe because the model was professionally trained"], correct:2, explanation:"Treating output as untrusted and validating or encoding it prevents downstream injection. Passing it into queries or executing it unreviewed causes classic injection flaws." },
  { id:2274, domain:5, level:2, question:"Which practice best supports rapid containment if a deployed model version is found to be compromised?", options:["Deploying models without version tags to keep the registry uncluttered","Overwriting the previous model in place so only one version ever exists","Maintaining versioned models and a tested rollback path to a known-good version","Disabling deployment automation so all changes require manual intervention"], correct:2, explanation:"Versioning plus a tested rollback path enables fast reversion to a trusted model. Overwriting in place or dropping version tags removes the ability to roll back cleanly." },
  { id:2275, domain:6, level:2, question:"Which is a primary reason to document the intended purpose of an AI system for compliance?", options:["Documentation automatically prevents the system from ever being misused","Purpose documentation removes the need to perform any risk assessment","It bounds acceptable use and supports evaluating proportionality and lawful basis","It guarantees the model will be classified as low-risk by any regulator"], correct:2, explanation:"Documented purpose bounds acceptable use and supports proportionality and lawful-basis analysis. It does not prevent misuse, replace risk assessment, or dictate a low-risk classification." },
  { id:2276, domain:1, level:2, question:"Which best characterizes the security value of post-quantum cryptographic agility?", options:["A technique that compresses ciphertext to reduce cloud storage consumption","A guarantee that current encryption can never be broken by any future computer","A method to permanently eliminate the need for any key management processes","The ability to swap cryptographic algorithms as quantum-resistant standards mature"], correct:3, explanation:"Crypto agility lets organizations adopt quantum-resistant algorithms as standards mature. It does not guarantee unbreakable encryption, remove key management, or compress data." },
  { id:2277, domain:2, level:2, question:"Which is the best approach to minimize PII exposure when logging LLM interactions for analytics?", options:["Applying redaction, aggregation, and retention limits to interaction analytics data","Sharing analytics logs with any team that requests them without restriction","Retaining analytics logs indefinitely so historical trends are never lost","Logging complete raw interactions including all personal data for richer analytics"], correct:0, explanation:"Redaction, aggregation, and retention limits minimize PII exposure in analytics logs. Logging raw data, unrestricted sharing, or indefinite retention all increase exposure." },
  { id:2278, domain:3, level:2, question:"Which is a primary security benefit of running AI inference workloads in a TEE?", options:["It automatically scales the inference service to handle any level of demand","It removes the requirement to encrypt the model artifacts stored at rest","It protects the model and data in use even from a compromised host OS","It guarantees the inference results will always be perfectly accurate"], correct:2, explanation:"A TEE protects data and model in use even if the host OS is compromised. It does not autoscale, remove at-rest encryption needs, or guarantee accuracy." },
  { id:2279, domain:4, level:3, question:"Why should an LLM application separate the model's instructions from untrusted user and retrieved content?", options:["Clear separation reduces the chance untrusted content is interpreted as trusted instructions","Separation guarantees the model will never produce a hallucinated response","Separation increases the maximum number of tokens the model can process as a general practice","Separation removes the need to validate any of the model's generated output"], correct:0, explanation:"Separating trusted instructions from untrusted content lowers the risk of injection being treated as commands. It does not expand token limits, prevent hallucination, or remove output validation needs." },
  { id:2280, domain:5, level:2, question:"Which is the most effective way to secure the pipeline that publishes a model to a production endpoint?", options:["Sharing a single deployment credential broadly to reduce coordination overhead","Allowing any engineer to deploy to production without review to move faster","Requiring signed artifacts, approval gates, and least-privilege deployment credentials","Disabling deployment logs so the pipeline generates less operational noise"], correct:2, explanation:"Signed artifacts, approvals, and least-privilege credentials secure the deployment pipeline. Unreviewed deploys, shared credentials, or disabled logs weaken pipeline security." },
  { id:2281, domain:6, level:2, question:"Which is a key consideration when relying on an AIaaS provider for a regulated workload?", options:["The provider automatically assumes full regulatory liability for the customer's use","Regulatory accountability cannot be outsourced; the customer remains responsible for compliance","Using AIaaS exempts the workload from all applicable data-protection regulations","The provider's certifications transfer directly to the customer without any review"], correct:1, explanation:"Accountability for compliance stays with the customer even when using AIaaS. Providers do not assume the customer's liability, and certifications do not transfer automatically." },
  { id:2282, domain:1, level:2, question:"Which best explains why zero trust favors continuous verification over one-time authentication?", options:["Context and risk can change after login, so access should be re-evaluated continuously","Continuous verification removes the need for any encryption of network traffic","Continuous verification lets the network be treated as fully trusted internally","Continuous verification permanently eliminates the possibility of credential theft"], correct:0, explanation:"Continuous verification re-evaluates access as risk and context change after login. It does not eliminate credential theft, remove encryption needs, or make internal networks trusted." },
  { id:2283, domain:2, level:2, question:"Which is the best control to prevent sensitive data from entering an LLM through the RAG corpus?", options:["Indexing all available documents so the model always has maximum context","Granting all users access to the entire corpus to simplify permission handling","Assuming indexed documents are safe because they came from internal systems","Classifying and filtering documents before indexing to exclude sensitive content"], correct:3, explanation:"Classifying and filtering documents before indexing keeps sensitive content out of the corpus. Indexing everything or assuming internal documents are safe risks exposing sensitive data." },
  { id:2284, domain:3, level:2, question:"Which is a primary benefit of policy-as-code admission control in Kubernetes?", options:["Automatically enforcing security policies on workloads before they are admitted","Guaranteeing that admitted workloads can never contain any vulnerabilities","Replacing the need for role-based access control on the cluster API server","Doubling the compute resources allocated to every workload that is admitted"], correct:0, explanation:"Policy-as-code admission control enforces policy before workloads are admitted. It does not guarantee vulnerability-free workloads, replace RBAC, or change resource allocation." },
  { id:2285, domain:4, level:2, question:"Which is the best way to defend an LLM feature against inputs designed to exhaust resources?", options:["Removing all input length limits so users can submit any prompt they wish","Enforcing input size limits, timeouts, and per-user rate limiting on requests","Disabling request timeouts so long-running requests always eventually complete","Trusting users not to submit maliciously large or complex inputs deliberately"], correct:1, explanation:"Input size limits, timeouts, and rate limiting defend against resource-exhaustion inputs. Removing limits, trusting users, or disabling timeouts invites denial-of-service abuse." },
  { id:2286, domain:5, level:2, question:"Which practice best supports detecting anomalous access to a cloud-hosted model API?", options:["Baselining normal usage and alerting on deviations in volume, source, or pattern","Logging only failed authentication attempts and ignoring successful requests","Disabling API access logs to reduce the total volume of stored telemetry","Assuming authenticated requests are always legitimate and need no monitoring"], correct:0, explanation:"Baselining usage and alerting on deviations detects anomalous access. Logging only failures, disabling logs, or trusting all authenticated requests misses abuse from valid credentials." },
  { id:2287, domain:6, level:2, question:"Which is a defining characteristic of the ISO/IEC 42001 approach to AI management?", options:["It prescribes the exact neural network architecture organizations must deploy","It follows a management-system model with continual improvement of AI governance","It bans the use of any third-party foundation models in regulated industries","It certifies individual models as safe after a mandatory government inspection"], correct:1, explanation:"ISO/IEC 42001 uses a management-system approach with continual improvement of AI governance. It does not prescribe architectures, certify individual models, or ban third-party models." },
  { id:2288, domain:1, level:2, question:"Which best describes why data residency requirements influence cloud AI architecture decisions?", options:["Certain data must remain in specific jurisdictions, constraining where models can process it","Data residency only affects backup schedules and never real-time model processing","Residency requirements are automatically satisfied by encrypting data in transit","Residency rules apply solely to physical media and never to cloud-hosted data"], correct:0, explanation:"Residency mandates constrain where data can be processed, shaping model-hosting choices. Encryption does not satisfy residency, which applies to cloud data, not just physical media." },
  { id:2289, domain:2, level:2, question:"Which is the best approach to safeguard embeddings that represent confidential source documents?", options:["Encrypting the vector store, restricting access, and isolating tenants appropriately","Publishing embeddings openly because they are mathematically impossible to reverse","Storing embeddings without access controls since they are just arrays of numbers","Sharing embedding keys widely so any service can decode them when needed"], correct:0, explanation:"Encryption, access restriction, and tenant isolation protect confidential embeddings. Treating embeddings as irreversible or removing access controls exposes the underlying data." },
  { id:2290, domain:3, level:2, question:"Which is a primary security consideration unique to serverless event-driven architectures?", options:["Serverless functions require the customer to patch the underlying host OS","Serverless functions must always run with full administrative privileges","Serverless functions cannot be integrated with any identity or access controls","Untrusted event sources can trigger functions, so event data must be validated"], correct:3, explanation:"Untrusted event sources can invoke functions, so event payloads must be validated. The provider patches the OS, and functions should run least-privilege, not as admins." },
  { id:2291, domain:4, level:2, question:"Which is the best mitigation against model-extraction attempts via a public inference API?", options:["Exposing the model with no authentication to maximize adoption metrics","Removing all query logging so probing activity leaves no forensic trace","Returning maximally detailed confidence scores to improve user transparency","Rate limiting, authentication, and monitoring for systematic probing query patterns"], correct:3, explanation:"Rate limiting, authentication, and probing-pattern monitoring raise the cost of extraction. Unauthenticated access, verbose confidence outputs, and no logging make extraction easier." },
  { id:2292, domain:5, level:3, question:"When an AI red-team exercise uncovers a reproducible jailbreak, what is the most appropriate response?", options:["Documenting it, adding guardrails or filters, and re-testing to confirm the fix","Publicly releasing the exact jailbreak prompt so users can avoid triggering it","Ignoring the finding since jailbreaks are inevitable and cannot be mitigated","Disabling the model entirely and permanently to guarantee it is never misused"], correct:0, explanation:"Documenting, adding guardrails, and re-testing closes the jailbreak methodically. Ignoring it, publicizing the exploit, or permanently disabling the model are inappropriate extremes." },
  { id:2293, domain:6, level:2, question:"Which is a primary reason organizations adopt the NIST AI RMF alongside existing security frameworks?", options:["It provides AI-specific risk guidance that complements broader security programs","It certifies AI systems as fully compliant, removing the need for other controls","It replaces all existing cybersecurity and privacy frameworks the organization uses","It mandates specific cloud providers for hosting all AI training workloads"], correct:0, explanation:"The AI RMF adds AI-specific risk guidance that complements existing programs. It neither replaces other frameworks, certifies systems, nor mandates specific providers." },
  { id:2294, domain:1, level:1, question:"What does CSPM primarily provide in a cloud environment?", options:["Encryption of all data in transit between microservices within a service mesh","Runtime memory protection for individual containers and serverless functions","Continuous visibility into misconfigurations and compliance posture of cloud resources","Lifecycle management of user identities within the corporate directory service"], correct:2, explanation:"CSPM continuously surfaces misconfigurations and compliance posture. Runtime protection, transit encryption, and identity lifecycle belong to CWPP, service mesh, and IAM." },
  { id:2295, domain:2, level:2, question:"Which is the best practice for handling secrets referenced within LLM prompts or tool configurations?", options:["Embedding secrets directly in prompts so the model can use them conveniently","Retrieving secrets from a managed vault at runtime and keeping them out of prompts","Storing secrets in prompt templates committed to the application repository","Logging secrets in plaintext with each request to aid future troubleshooting"], correct:1, explanation:"Fetching secrets from a vault at runtime and keeping them out of prompts prevents leakage. Embedding in prompts, committing to repos, or logging in plaintext exposes them." },
  { id:2296, domain:3, level:2, question:"Which is a primary benefit of network micro-segmentation in a cloud-native environment?", options:["It removes the requirement to authenticate any traffic within a trusted zone","It confines a compromised workload, limiting lateral movement to a small zone","It automatically encrypts all persistent storage volumes attached to workloads","It guarantees that every workload receives identical inbound bandwidth"], correct:1, explanation:"Micro-segmentation confines a compromise and limits lateral movement. It does not remove authentication needs, encrypt storage, or equalize bandwidth." },
  { id:2297, domain:4, level:2, question:"Which is the best mitigation for the risk that a RAG system surfaces documents a user cannot access?", options:["Filtering results only after generation so the model still sees restricted context","Trusting the model to omit content the user is not authorized to view","Assuming all indexed documents are safe for every user to retrieve freely","Enforcing the user's access rights at retrieval time before context reaches the model"], correct:3, explanation:"Enforcing access rights at retrieval keeps unauthorized documents out of the model's context. Post-generation filtering still exposes restricted content to the model, risking leakage." },
  { id:2298, domain:5, level:1, question:"What is the primary purpose of secrets rotation in cloud security operations?", options:["Increasing the entropy of every password to make them impossible to guess","Limiting the exposure window if a credential is compromised by regularly replacing it","Reducing storage costs by shortening the length of stored credential values","Eliminating the need to encrypt credentials while they are stored at rest"], correct:1, explanation:"Rotation limits the window a compromised credential remains useful. It is not about entropy, storage cost, or removing the need for encryption at rest." },
  { id:2299, domain:6, level:2, question:"Which is a key reason to maintain human oversight of high-impact AI decisions under emerging regulation?", options:["Human oversight increases the raw speed at which decisions are delivered to users","Human oversight removes the organization's accountability for the AI's decisions","Human oversight enables review, contestation, and override of consequential outcomes","Human oversight eliminates the requirement to document the decision process"], correct:2, explanation:"Oversight lets humans review, contest, and override high-impact decisions. It does not speed decisions, remove accountability, or eliminate documentation requirements." },
  { id:2300, domain:1, level:2, question:"Which best describes the security significance of an SBOM for AI applications?", options:["It inventories software and model components so vulnerabilities can be traced quickly","It automatically patches every vulnerable component listed within the inventory","It guarantees the application contains no vulnerable dependencies whatsoever","It replaces the need for any runtime monitoring of the deployed application"], correct:0, explanation:"An SBOM inventories components so affected ones can be located during a vulnerability event. It does not auto-patch, guarantee zero vulnerabilities, or replace runtime monitoring." }
];
if (typeof window !== 'undefined') window.QUESTIONS_CCSP_C7 = QUESTIONS_CCSP_C7;
